import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";
import { getToken } from "next-auth/jwt";
import { protectedRouteMap } from "@/lib/auth/routes";

const SECRET = process.env.NEXTAUTH_SECRET;

export async function middleware(req: NextRequest) {
  const { pathname } = req.nextUrl;

  // Only run protection for configured prefixes
  const rule = protectedRouteMap.find((r) => pathname.startsWith(r.prefix));
  if (!rule) return NextResponse.next();

  // Read token from NextAuth JWT cookie
  const token = await getToken({ req });

  if (!token) {
    // Not signed in -> redirect to sign in
    const url = req.nextUrl.clone();
    url.pathname = "/login";
    url.search = `from=${encodeURIComponent(pathname)}`;
    return NextResponse.redirect(url);
  }

  const role =
    token && typeof token === "object" && "role" in token
      ? (token as { role?: string }).role
      : undefined;

  if (!role || !rule.roles.includes(role)) {
    // Signed in but wrong role -> redirect to unauthorized page
    const url = req.nextUrl.clone();
    url.pathname = "/unauthorized";
    return NextResponse.rewrite(url);
  }

  return NextResponse.next();
}

// Statically list matchers so Next.js can statically analyze the config.
export const config = {
  matcher: [
    "/buyer/:path*",
    "/seller/:path*",
  ],
};

"use client";

import React, { useState, useEffect, useMemo } from "react";
import { 
  Search, 
  Plus, 
  ChevronDown, 
  MoreHorizontal,
  Download,
  Bell,
  Edit2,
  Trash2,
  ExternalLink
} from "lucide-react";
import Link from "next/link";
import { useNotification } from "@/context/NotificationContext";
import { apiFetch } from "@/services/apiClient";

const statusStyles = {
  active: "bg-[#10B981] text-white",
  published: "bg-[#10B981] text-white",
  draft: "bg-[#0EA5E9] text-white",
  scheduled: "bg-[#F59E0B]/80 text-white",
  expired: "bg-[#4B5563] text-white",
  sold: "bg-zinc-700 text-white",
  closed: "bg-zinc-400 text-white",
};

function formatTimeAgo(dateString: string) {
  const date = new Date(dateString);
  const now = new Date();
  const seconds = Math.floor((now.getTime() - date.getTime()) / 1000);

  if (seconds < 60) return "just now";
  const minutes = Math.floor(seconds / 60);
  if (minutes < 60) return `${minutes} minutes ago`;
  const hours = Math.floor(minutes / 60);
  if (hours < 24) return `${hours} hours ago`;
  const days = Math.floor(hours / 24);
  if (days < 30) return `${days} days ago`;
  return date.toLocaleDateString();
}

export default function DealsManagementPage() {
  const { showNotification } = useNotification();
  const [deals, setDeals] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");
  const [statusFilter, setStatusFilter] = useState("All Status");
  const [activeMenuId, setActiveMenuId] = useState<number | null>(null);

  useEffect(() => {
    async function loadDeals() {
      try {
        const result = await apiFetch<{ success: boolean; data: any[] }>("admin/deals", {}, true);
        if (result.success) {
          setDeals(result.data);
        }
      } catch (err) {
        console.error("Failed to load deals", err);
      } finally {
        setLoading(false);
      }
    }
    loadDeals();
  }, []);

  const filteredDeals = useMemo(() => {
    return deals.filter(deal => {
      const matchSearch = (deal.title || "").toLowerCase().includes(searchTerm.toLowerCase());
      const matchStatus = statusFilter === "All Status" || (deal.status || "").toLowerCase() === statusFilter.toLowerCase();
      return matchSearch && matchStatus;
    });
  }, [deals, searchTerm, statusFilter]);

  const handleDelete = async (id: number) => {
    try {
      const result = await apiFetch<{ success: boolean }>(`admin/deals/${id}`, { method: "DELETE" }, true);
      if (result.success) {
        setDeals(prev => prev.filter(d => d.id !== id));
        showNotification("warning", "Deal removed successfully.");
      }
    } catch (err) {
      showNotification("error", "Failed to delete deal.");
    }
    setActiveMenuId(null);
  };

  if (loading) return <div className="p-20 text-center font-bold text-orange-600 text-2xl">Loading deals...</div>;

  return (
    <div className="space-y-8 font-bold">
      {/* Header Section */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl text-zinc-900 font-bold">Deals Management</h1>
          <p className="text-zinc-500 text-sm mt-1 font-medium">Manage all deals and promotions</p>
        </div>
        <div className="flex items-center gap-3">
          <button className="flex items-center gap-2 px-4 py-2 border border-[#E85A28] text-[#E85A28] rounded-lg bg-white hover:bg-orange-50 transition-colors text-sm font-bold shadow-sm active:scale-95">
            <Download size={16} />
            Export
          </button>
          <button className="relative p-2 border border-zinc-200 rounded-lg hover:bg-zinc-50 transition-colors shadow-sm">
            <Bell size={20} className="text-zinc-600" />
            <span className="absolute top-1 right-1.5 w-2 h-2 bg-orange-500 rounded-full border-2 border-white"></span>
          </button>
        </div>
      </div>

      {/* Main Content Card */}
      <div className="bg-white rounded-2xl border border-zinc-200 shadow-sm overflow-hidden">
        <div className="p-6 border-b border-zinc-100">
          <div className="flex flex-col gap-6">
            <div>
              <h2 className="text-lg text-zinc-900 font-bold">All Deals</h2>
              <p className="text-sm text-zinc-500 font-medium">Manage and monitor all deals on the platform</p>
            </div>

            {/* Filters and Actions Bar */}
            <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4">
              <div className="flex flex-col sm:flex-row items-center gap-3 flex-1 lg:max-w-3xl">
                {/* Search */}
                <div className="relative flex-1 w-full font-bold">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-400" size={20} />
                  <input
                    type="text"
                    placeholder="Search here..."
                    className="w-full pl-10 pr-4 py-2.5 bg-zinc-50 border border-zinc-200 rounded-lg outline-none focus:border-orange-500 transition-colors text-zinc-700 font-medium"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                  />
                </div>

                {/* Status Dropdown */}
                <div className="relative w-full sm:w-48">
                  <select 
                    value={statusFilter}
                    onChange={(e) => setStatusFilter(e.target.value)}
                    className="w-full appearance-none bg-zinc-50 border border-zinc-200 rounded-lg px-4 py-2.5 outline-none focus:border-orange-500 text-zinc-700 font-bold cursor-pointer"
                  >
                    <option>All Status</option>
                    <option>Active</option>
                    <option>Draft</option>
                    <option>Scheduled</option>
                    <option>Expired</option>
                  </select>
                  <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-zinc-400 pointer-events-none" size={18} />
                </div>
              </div>

              {/* Add New Deal Button */}
              <Link 
                href="/admin/deals/new"
                className="flex items-center justify-center gap-2 bg-[#E85A28] text-white px-6 py-2.5 rounded-lg hover:bg-[#D14F23] transition-colors font-bold shadow-md shadow-[#E85A28]/20 active:scale-95"
              >
                <Plus size={20} />
                Add New Deal
              </Link>
            </div>
          </div>
        </div>

        {/* Table */}
        <div className="overflow-x-auto min-h-[400px]">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-zinc-50 text-zinc-500 text-[11px] font-black uppercase tracking-widest border-b border-zinc-100">
                <th className="px-6 py-5">Deal Title</th>
                <th className="px-6 py-5">Price</th>
                <th className="px-6 py-5">Merchant</th>
                <th className="px-6 py-5">Category</th>
                <th className="px-6 py-5 text-center">Status</th>
                <th className="px-6 py-5 text-right">Clicks</th>
                <th className="px-6 py-5 text-right whitespace-nowrap">Last Updated</th>
                <th className="px-6 py-5 text-center">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-zinc-100 italic">
              {filteredDeals.map((deal) => (
                <tr key={deal.id} className="hover:bg-zinc-50/80 transition-colors group">
                  <td className="px-6 py-6 max-w-[240px]">
                    <span className="text-[15px] font-black text-zinc-900 leading-tight block">{deal.title}</span>
                  </td>
                  <td className="px-6 py-6 font-black">
                    <span className="text-[15px] text-zinc-900">₦{Number(deal.price).toLocaleString()}</span>
                  </td>
                  <td className="px-6 py-6">
                    <span className="text-[14px] text-zinc-500 font-bold">{deal.merchant || "Unknown"}</span>
                  </td>
                  <td className="px-6 py-6">
                    <span className="text-[14px] text-zinc-400 font-medium whitespace-nowrap">{deal.category || "General"}</span>
                  </td>
                  <td className="px-6 py-6 text-center">
                    <span className={`inline-block px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-wider ${statusStyles[deal.status as keyof typeof statusStyles] || "bg-gray-400 text-white"}`}>
                      {deal.status}
                    </span>
                  </td>
                  <td className="px-6 py-6 text-right">
                    <span className="text-[14px] text-zinc-600 font-bold">{deal.clicks?.toLocaleString() || 0}</span>
                  </td>
                  <td className="px-6 py-6 text-right whitespace-nowrap">
                    <span className="text-[14px] text-zinc-400 font-medium">{formatTimeAgo(deal.updatedAt)}</span>
                  </td>
                  <td className="px-6 py-6 text-center relative">
                    <button 
                      onClick={() => setActiveMenuId(activeMenuId === deal.id ? null : deal.id)}
                      className="p-2 text-zinc-300 hover:text-zinc-600 rounded-full hover:bg-zinc-100 transition-all active:scale-95"
                    >
                      <MoreHorizontal size={22} />
                    </button>
                    
                    {/* Floating Action Menu */}
                    {activeMenuId === deal.id && (
                      <div className="absolute right-14 top-4 z-50 w-52 bg-white border border-zinc-200 rounded-2xl shadow-2xl py-3 animate-in zoom-in-95 duration-200 font-bold text-sm not-italic">
                        <Link 
                          href={`/admin/deals/edit/${deal.id}`}
                          className="flex items-center gap-3 px-5 py-2.5 text-zinc-700 hover:bg-zinc-50 transition-colors"
                        >
                          <Edit2 size={18} className="text-orange-500" />
                          Edit Deal
                        </Link>
                        <Link 
                          href={`/product/${deal.id}`}
                          className="w-full flex items-center gap-3 px-5 py-2.5 text-zinc-700 hover:bg-zinc-50 transition-colors"
                        >
                          <ExternalLink size={18} className="text-blue-500" />
                          View Page
                        </Link>
                        <div className="h-px bg-zinc-100 my-2 mx-3" />
                        <button 
                          onClick={() => handleDelete(deal.id)}
                          className="w-full flex items-center gap-3 px-5 py-2.5 text-red-600 hover:bg-red-50 transition-colors"
                        >
                          <Trash2 size={18} />
                          Delete Deal
                        </button>
                      </div>
                    )}
                  </td>
                </tr>
              ))}
              {filteredDeals.length === 0 && (
                <tr>
                  <td colSpan={8} className="px-6 py-32 text-center text-zinc-400 font-bold italic text-lg">
                    No deals found matching your criteria.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
      
      {/* Click outside backdrop for menu */}
      {activeMenuId && (
        <div className="fixed inset-0 z-40 bg-transparent" onClick={() => setActiveMenuId(null)} />
      )}
    </div>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import { 
  Package, 
  CheckCircle2, 
  FileEdit, 
  Calendar, 
  MousePointer2,
  Download,
  Bell
} from "lucide-react";
import StatCard from "@/components/admin/StatCard";
import { API_BASE } from "@/services/apiClient";
import VendorManagement from "@/components/admin/VendorManagement";
import VendorApplications from "@/components/admin/VendorApplications";

import { 
  ResponsiveContainer, 
  AreaChart, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip,
  BarChart,
  Bar,
  Cell
} from "recharts";

export default function AdminDashboardPage() {
  const [data, setData] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [clicksTrend, setClicksTrend] = useState<any[]>([]);

  useEffect(() => {
    async function loadStats() {
      try {
        const token = typeof window !== "undefined" ? window.localStorage.getItem("token") : null;
        if (!token) return;

        // Fetch summary
        const res = await fetch(`${API_BASE}/admin/analytics/summary`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        const summary = await res.json();
        if (summary.success) {
          setData(summary.data);
        }

        // Fetch clicks trend
        const trendRes = await fetch(`${API_BASE}/admin/analytics/clicks-by-day`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        const trend = await trendRes.json();
        if (trend.success) {
          const days = ["Sun", "Mon", "Tue", "Wed", "Thur", "Fri", "Sat"];
          const mappedTrend = trend.data.slice(0, 7).reverse().map((d: any) => ({
            name: days[new Date(d.day).getDay()],
            clicks: d.views
          }));
          setClicksTrend(mappedTrend);
        }
      } catch (err) {
        console.error("Failed to load admin stats", err);
      } finally {
        setLoading(false);
      }
    }
    loadStats();
  }, []);

  if (loading) return <div className="p-20 text-center font-bold text-orange-600 text-2xl">Loading overview...</div>;

  return (
    <div className="space-y-8">
      {/* Header Section */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-zinc-900">Dashboard Overview</h1>
          <p className="text-zinc-500 text-sm mt-1">Monitor your platform performance</p>
        </div>
        <div className="flex items-center gap-3">
          <button className="flex items-center gap-2 px-4 py-2 border border-zinc-200 rounded-lg hover:bg-zinc-50 transition-colors text-sm font-semibold">
            <Download size={16} />
            Export
          </button>
          <button className="relative p-2 border border-zinc-200 rounded-lg hover:bg-zinc-50 transition-colors">
            <Bell size={20} className="text-zinc-600" />
            <span className="absolute top-1 right-1.5 w-2 h-2 bg-orange-500 rounded-full border-2 border-white"></span>
          </button>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
        <StatCard
          label="Total Deals"
          value={String(data?.total_deals || 0)}
          icon={Package}
          trend={{ value: "+12%", isUp: true }}
          color="orange"
          bgColor="bg-[#E85A28]"
          iconColor="text-white"
        />
        <StatCard
          label="Published"
          value={String(data?.published || 0)}
          icon={CheckCircle2}
          color="green"
          bgColor="bg-[#22C55E]"
          iconColor="text-white"
        />
        <StatCard
          label="Draft"
          value={String(data?.drafts || 0)}
          icon={FileEdit}
          color="yellow"
          bgColor="bg-[#FACC15]"
          iconColor="text-white"
        />
        <StatCard
          label="Scheduled"
          value={String(data?.scheduled || 0)}
          icon={Calendar}
          trend={{ value: "2 upcoming", isUp: true }}
          color="purple"
          bgColor="bg-[#A855F7]"
          iconColor="text-white"
        />
        <StatCard
          label="Total Clicks"
          value={String(data?.total_views || 0)}
          icon={MousePointer2}
          trend={{ value: "+12%", isUp: true }}
          color="green"
          bgColor="bg-[#22C55E]"
          iconColor="text-white"
        />
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-2xl border border-zinc-200 shadow-sm">
          <div className="flex items-center justify-between mb-6">
            <h3 className="font-bold text-zinc-900">Clicks Trend</h3>
            <button className="bg-[#E85A28] text-white text-[12px] font-bold px-3 py-1.5 rounded-lg active:scale-95 transition-transform">
              Last 7 days
            </button>
          </div>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={clicksTrend}>
                <defs>
                  <linearGradient id="colorClicks" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#E85A28" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#E85A28" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#F3F4F6" />
                <XAxis 
                  dataKey="name" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 12, fill: '#9CA3AF' }}
                  dy={10}
                />
                <YAxis 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 12, fill: '#9CA3AF' }}
                />
                <Tooltip 
                  contentStyle={{ 
                    borderRadius: '12px', 
                    border: 'none', 
                    boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' 
                  }} 
                />
                <Area 
                  type="monotone" 
                  dataKey="clicks" 
                  stroke="#E85A28" 
                  strokeWidth={2}
                  fillOpacity={1} 
                  fill="url(#colorClicks)" 
                  dot={{ r: 4, fill: '#E85A28', strokeWidth: 2, stroke: '#fff' }}
                  activeDot={{ r: 6, fill: '#E85A28', strokeWidth: 2, stroke: '#fff' }}
                />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-zinc-200 shadow-sm">
          <div className="flex items-center justify-between mb-6">
            <h3 className="font-bold text-zinc-900">Deals by category</h3>
          </div>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={data?.categories || []} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#F3F4F6" />
                <XAxis 
                  dataKey="name" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 10, fill: '#9CA3AF' }}
                  dy={10}
                />
                <YAxis 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 12, fill: '#9CA3AF' }}
                />
                <Tooltip 
                  contentStyle={{ 
                    borderRadius: '12px', 
                    border: 'none', 
                    boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' 
                  }} 
                />
                <Bar dataKey="value" radius={[4, 4, 0, 0]} barSize={30}>
                  {(data?.categories || []).map((entry: any, index: number) => (
                    <Cell key={`cell-${index}`} fill="#FACC15" />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      <VendorManagement />
      <VendorApplications />

      {/* Recent Deals Table Placeholder */}
      <div className="bg-white rounded-2xl border border-zinc-200 shadow-sm overflow-hidden">
        <div className="p-6 border-b border-zinc-100 flex items-center justify-between">
          <div>
            <h3 className="font-bold text-zinc-900">Recent Deals</h3>
            <p className="text-zinc-500 text-xs mt-0.5">Latest deals added to the platform</p>
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-zinc-50 text-zinc-500 text-[12px] font-bold uppercase tracking-wider">
                <th className="px-6 py-4">Deal Title</th>
                <th className="px-6 py-4">Merchant</th>
                <th className="px-6 py-4">Status</th>
                <th className="px-6 py-4 text-right">Clicks</th>
                <th className="px-6 py-4 text-right">Last Updated</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-zinc-100">
              {(data?.recentDeals || []).map((deal: any) => (
                <tr key={deal.id} className="hover:bg-zinc-50 transition-colors">
                  <td className="px-6 py-4 text-sm font-semibold text-zinc-900">{deal.title}</td>
                  <td className="px-6 py-4 text-sm text-zinc-600">{deal.merchant || "Unknown"}</td>
                  <td className="px-6 py-4">
                    <span className={`px-2.5 py-1 text-white text-[11px] font-bold rounded ${
                      deal.status === 'active' ? 'bg-[#10B981]' : 
                      deal.status === 'draft' ? 'bg-[#FACC15]' : 'bg-[#A855F7]'
                    }`}>
                      {deal.status}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-sm text-zinc-600 text-right">{deal.views?.toLocaleString()}</td>
                  <td className="px-6 py-4 text-sm text-zinc-600 text-right">{new Date(deal.updatedAt).toLocaleDateString()}</td>
                </tr>
              ))}
              {(!data?.recentDeals || data.recentDeals.length === 0) && (
                <tr>
                  <td colSpan={5} className="py-20 text-center text-zinc-400 font-bold">No deals recorded yet.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

"use client";
import React, { useEffect, useState } from "react";
import { 
  CheckCircle2, 
  XCircle, 
  Eye, 
  Clock, 
  Search,
  ChevronLeft,
  ChevronRight,
  MoreVertical,
  ExternalLink,
  MapPin,
  Tag
} from "lucide-react";
import { getAdminSubmissions, updateAdminSubmissionStatus } from "@/lib/api";
import { toast } from "react-hot-toast";

interface Submission {
  id: number;
  title: string;
  price: number;
  status: "PENDING" | "APPROVED" | "REJECTED";
  created_at: string;
  image_url: string | null;
  images_json: string | null;
  condition?: string;
  brand?: string;
  model?: string;
  state?: string;
  city?: string;
  user_id: number;
}

export default function SubmissionsPage() {
  const [submissions, setSubmissions] = useState<Submission[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedSubmission, setSelectedSubmission] = useState<Submission | null>(null);
  const [isUpdating, setIsUpdating] = useState(false);

  useEffect(() => {
    fetchSubmissions();
  }, []);

  const fetchSubmissions = async () => {
    setLoading(true);
    try {
      const res = await getAdminSubmissions();
      if (res.success) {
        setSubmissions(res.data);
      }
    } catch (error) {
      toast.error("Failed to fetch submissions");
    } finally {
      setLoading(false);
    }
  };

  const handleStatusUpdate = async (id: number, status: "APPROVED" | "REJECTED") => {
    setIsUpdating(true);
    try {
      const res = await updateAdminSubmissionStatus(id, status);
      if (res.success) {
        toast.success(`Submission ${status === "APPROVED" ? "approved" : "rejected"}!`);
        fetchSubmissions();
        setSelectedSubmission(null);
      }
    } catch (error) {
      toast.error("Failed to update status");
    } finally {
      setIsUpdating(false);
    }
  };

  const filteredSubmissions = submissions.filter(sub => 
    sub.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
    sub.status.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="p-6 lg:p-10 space-y-8 max-w-[1600px] mx-auto animate-in fade-in duration-500">
      {/* Header Section */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-black text-black">Ad Submissions</h1>
          <p className="text-zinc-500 font-bold mt-1">Review and manage pending vendor ads</p>
        </div>
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-400" size={20} />
          <input
            type="text"
            placeholder="Search ads or status..."
            className="pl-10 pr-4 py-3 bg-white border border-zinc-200 rounded-xl w-full md:w-[320px] focus:outline-none focus:border-[#E85A28] transition-all font-bold"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
        </div>
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center py-20 gap-4">
          <div className="w-12 h-12 border-4 border-[#E85A28] border-t-transparent rounded-full animate-spin" />
          <p className="font-black text-zinc-500">Loading submissions...</p>
        </div>
      ) : filteredSubmissions.length === 0 ? (
        <div className="bg-white border border-zinc-200 rounded-2xl p-16 text-center shadow-sm">
          <div className="w-20 h-20 bg-zinc-50 rounded-full flex items-center justify-center mx-auto mb-6">
            <ClipboardListIcon />
          </div>
          <h2 className="text-2xl font-black text-black mb-2">No submissions found</h2>
          <p className="text-zinc-500 font-bold">All caught up! No pending ads to review currently.</p>
        </div>
      ) : (
        /* Submissions Table */
        <div className="bg-white border border-zinc-200 rounded-2xl overflow-hidden shadow-sm">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-zinc-50 border-b border-zinc-100">
                  <th className="px-6 py-4 font-black text-zinc-600 text-[13px] uppercase tracking-wider">Product Info</th>
                  <th className="px-6 py-4 font-black text-zinc-600 text-[13px] uppercase tracking-wider">Status</th>
                  <th className="px-6 py-4 font-black text-zinc-600 text-[13px] uppercase tracking-wider">Price</th>
                  <th className="px-6 py-4 font-black text-zinc-600 text-[13px] uppercase tracking-wider">Date Submitted</th>
                  <th className="px-6 py-4 font-black text-zinc-600 text-[13px] uppercase tracking-wider text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-zinc-50">
                {filteredSubmissions.map((sub) => (
                  <tr key={sub.id} className="hover:bg-zinc-50/50 transition-colors group">
                    <td className="px-6 py-5">
                      <div className="flex items-center gap-4">
                        <div className="w-14 h-14 bg-zinc-100 rounded-xl overflow-hidden border border-zinc-200 flex-shrink-0">
                          {sub.image_url ? (
                            <img src={sub.image_url} alt={sub.title} className="w-full h-full object-cover" />
                          ) : (
                            <div className="w-full h-full flex items-center justify-center text-zinc-400">
                              <Tag size={20} />
                            </div>
                          )}
                        </div>
                        <div>
                          <p className="font-black text-black hover:text-[#E85A28] transition-colors cursor-pointer" onClick={() => setSelectedSubmission(sub)}>
                            {sub.title}
                          </p>
                          <p className="text-zinc-400 text-xs font-bold mt-0.5">{sub.brand} {sub.model}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-5">
                      <StatusBadge status={sub.status} />
                    </td>
                    <td className="px-6 py-5 font-black text-zinc-900">
                      ₦{sub.price.toLocaleString()}
                    </td>
                    <td className="px-6 py-5 text-zinc-500 font-bold text-sm">
                      {new Date(sub.created_at).toLocaleDateString()}
                    </td>
                    <td className="px-6 py-5 text-right">
                      <div className="flex items-center justify-end gap-2">
                        <button 
                          onClick={() => setSelectedSubmission(sub)}
                          className="p-2 text-zinc-400 hover:text-black hover:bg-zinc-100 rounded-lg transition-all"
                          title="View Details"
                        >
                          <Eye size={20} />
                        </button>
                        {sub.status === "PENDING" && (
                          <>
                            <button 
                              onClick={() => handleStatusUpdate(sub.id, "APPROVED")}
                              className="p-2 text-green-500 hover:bg-green-50 rounded-lg transition-all"
                              title="Approve"
                            >
                              <CheckCircle2 size={20} />
                            </button>
                            <button 
                              onClick={() => handleStatusUpdate(sub.id, "REJECTED")}
                              className="p-2 text-red-500 hover:bg-red-50 rounded-lg transition-all"
                              title="Reject"
                            >
                              <XCircle size={20} />
                            </button>
                          </>
                        )}
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Details Modal */}
      {selectedSubmission && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-3xl overflow-hidden max-w-2xl w-full shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="relative aspect-video bg-zinc-100 border-b border-zinc-100">
              {selectedSubmission.image_url ? (
                <img src={selectedSubmission.image_url} alt={selectedSubmission.title} className="w-full h-full object-cover" />
              ) : (
                <div className="w-full h-full flex items-center justify-center text-zinc-300">
                   <Tag size={48} />
                </div>
              )}
              <div className="absolute top-4 right-4">
                <button 
                  onClick={() => setSelectedSubmission(null)}
                  className="bg-black/40 hover:bg-black/60 text-white p-2 rounded-full backdrop-blur-md transition-all"
                >
                  <XCircle size={24} />
                </button>
              </div>
              <div className="absolute bottom-4 left-4 flex gap-2">
                 <StatusBadge status={selectedSubmission.status} />
              </div>
            </div>

            <div className="p-8 space-y-6">
              <div className="flex justify-between items-start gap-4">
                <div>
                  <h3 className="text-2xl font-black text-black">{selectedSubmission.title}</h3>
                  <div className="flex items-center gap-2 text-zinc-500 font-bold text-sm mt-1">
                    <MapPin size={14} className="text-[#E85A28]" />
                    {selectedSubmission.city}, {selectedSubmission.state}
                  </div>
                </div>
                <div className="text-right">
                  <div className="text-[#E85A28] text-2xl font-black">₦{selectedSubmission.price.toLocaleString()}</div>
                  <div className="text-zinc-400 text-xs font-bold mt-1">PRICE</div>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <DetailBox label="Brand" value={selectedSubmission.brand || "N/A"} />
                <DetailBox label="Model" value={selectedSubmission.model || "N/A"} />
                <DetailBox label="Condition" value={selectedSubmission.condition || "N/A"} />
                <DetailBox label="Vendor ID" value={`#${selectedSubmission.user_id}`} />
              </div>

              {selectedSubmission.status === "PENDING" && (
                <div className="flex gap-4 pt-4">
                  <button 
                    disabled={isUpdating}
                    onClick={() => handleStatusUpdate(selectedSubmission.id, "REJECTED")}
                    className="flex-1 bg-zinc-100 hover:bg-zinc-200 text-zinc-700 font-black py-4 rounded-2xl transition-all disabled:opacity-50"
                  >
                    Reject Ad
                  </button>
                  <button 
                    disabled={isUpdating}
                    onClick={() => handleStatusUpdate(selectedSubmission.id, "APPROVED")}
                    className="flex-1 bg-[#E85A28] hover:bg-[#D44D1F] text-white font-black py-4 rounded-2xl transition-all shadow-lg shadow-orange-100 disabled:opacity-50"
                  >
                    {isUpdating ? "Approving..." : "Approve Ad"}
                  </button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function StatusBadge({ status }: { status: string }) {
  const styles = {
    PENDING: "bg-orange-50 text-orange-600 border-orange-100",
    APPROVED: "bg-green-50 text-green-600 border-green-100",
    REJECTED: "bg-red-50 text-red-600 border-red-100",
  };

  const colors = styles[status as keyof typeof styles] || "bg-zinc-50 text-zinc-600 border-zinc-100";

  return (
    <span className={`px-3 py-1 rounded-full text-[11px] font-black border uppercase tracking-wider ${colors}`}>
      {status}
    </span>
  );
}

function DetailBox({ label, value }: { label: string, value: string }) {
  return (
    <div className="p-4 bg-zinc-50 border border-zinc-100 rounded-2xl">
      <div className="text-zinc-400 text-[10px] font-black uppercase mb-1">{label}</div>
      <div className="text-black font-bold text-sm">{value}</div>
    </div>
  );
}

function ClipboardListIcon() {
  return (
    <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="#D4D4D8" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
      <path d="M16 4h2a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2H6a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2h2" />
      <rect x="8" y="2" width="8" height="4" rx="1" ry="1" />
      <path d="M9 12h6" />
      <path d="M9 16h6" />
      <path d="M9 8h6" />
    </svg>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import { 
  Plus, 
  Search, 
  MoreHorizontal, 
  Trash2,
  Edit,
  Download,
  Bell
} from "lucide-react";
import AddTaxonomyModal from "@/components/admin/taxonomy/AddTaxonomyModal";
import { useNotification } from "@/context/NotificationContext";
import { API_BASE } from "@/services/apiClient";

export default function TaxonomyManagementPage() {
  const { showNotification } = useNotification();
  const [activeTab, setActiveTab] = useState<"Categories" | "Tags" | "Merchants">("Categories");
  const [isModalOpen, setIsModalOpen] = useState(false);
  
  const [categories, setCategories] = useState<any[]>([]);
  const [merchants, setMerchants] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function loadData() {
      try {
        const token = typeof window !== "undefined" ? window.localStorage.getItem("token") : null;
        if (!token) return;

        setLoading(true);
        // Fetch categories
        const catRes = await fetch(`${API_BASE}/admin/categories`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        const catData = await catRes.json();
        if (catData.success) {
          setCategories(catData.data || []);
        }

        // Fetch merchants (vendors)
        const merRes = await fetch(`${API_BASE}/users?role=vendor`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        const merData = await merRes.json();
        if (merData.success) {
          setMerchants(merData.data || []);
        }

      } catch (err) {
        console.error("Failed to load taxonomy data", err);
      } finally {
        setLoading(false);
      }
    }
    loadData();
  }, [API_BASE]);

  const handleDelete = async (type: string, id: number, name: string) => {
    try {
      const token = typeof window !== "undefined" ? window.localStorage.getItem("token") : null;
      const endpoint = type === "Categories" ? `/admin/categories/${id}` : `/users/${id}`;
      
      const res = await fetch(`${API_BASE}${endpoint}`, {
        method: "DELETE",
        headers: { Authorization: `Bearer ${token}` }
      });
      const result = await res.json();
      if (result.success) {
        if (type === "Categories") setCategories(prev => prev.filter(c => c.id !== id));
        else setMerchants(prev => prev.filter(m => m.id !== id));
        showNotification("warning", `${name} deleted.`);
      }
    } catch (err) {
      showNotification("error", `Failed to delete ${name}.`);
    }
  };

  if (loading) return <div className="p-20 text-center font-bold text-orange-600 text-2xl">Loading taxonomy...</div>;

  const categoryIcons: Record<string, string> = {
    "Electronics": "📱",
    "Fashion": "👗",
    "Home & Kitchen": "🍳",
    "Phones": "📱",
    "Gaming": "🎮",
    "Vehicle": "🚗",
    "Babies & Kids": "🧸",
    "Health & Beauty": "💄",
  };

  return (
    <div className="space-y-8 font-bold">
      {/* Header Section */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-zinc-900">Taxonomy Management</h1>
          <p className="text-zinc-500 text-sm mt-1 font-medium italic">Manage categories, tags and merchant profiles</p>
        </div>
        <div className="flex items-center gap-3">
          <button className="flex items-center gap-2 px-4 py-2 border border-[#E85A28] text-[#E85A28] rounded-lg bg-white hover:bg-orange-50 transition-colors text-sm font-bold shadow-sm active:scale-95">
            <Download size={16} />
            Export
          </button>
          <button className="relative p-2 border border-zinc-200 rounded-lg hover:bg-zinc-50 transition-colors shadow-sm">
            <Bell size={20} className="text-zinc-600" />
            <span className="absolute top-1 right-1.5 w-2 h-2 bg-orange-500 rounded-full border-2 border-white"></span>
          </button>
        </div>
      </div>

      {/* Main Content Card */}
      <div className="bg-white rounded-2xl border border-zinc-200 shadow-sm overflow-hidden">
        {/* Tab Navigation */}
        <div className="flex p-2 bg-zinc-50 border-b border-zinc-100">
          {["Categories", "Tags", "Merchants"].map((tab) => (
            <button
              key={tab}
              onClick={() => setActiveTab(tab as any)}
              className={`flex-1 py-3 text-sm font-bold rounded-xl transition-all ${
                activeTab === tab 
                  ? "bg-white text-[#E85A28] shadow-sm shadow-orange-500/10" 
                  : "text-zinc-500 hover:text-zinc-700 hover:bg-zinc-100/50"
              }`}
            >
              {tab}
            </button>
          ))}
        </div>

        <div className="p-6">
          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
            <div className="relative flex-1 md:max-w-md font-bold">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-400" size={18} />
              <input
                type="text"
                placeholder={`Search ${activeTab}...`}
                className="w-full pl-10 pr-4 py-2.5 bg-zinc-50 border border-zinc-200 rounded-lg outline-none focus:border-orange-500 transition-colors text-sm font-medium"
              />
            </div>
            <button 
              onClick={() => setIsModalOpen(true)}
              className="flex items-center justify-center gap-2 bg-[#E85A28] text-white px-6 py-2.5 rounded-lg hover:bg-[#D14F23] transition-colors font-bold shadow-md shadow-[#E85A28]/20 active:scale-95"
            >
              <Plus size={20} />
              Add {activeTab.slice(0, -1)}
            </button>
          </div>

          {/* Table Content */}
          <div className="overflow-x-auto border border-zinc-50 rounded-xl">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-zinc-50 text-zinc-500 text-[12px] font-bold uppercase tracking-wider italic">
                  <th className="px-6 py-4">Categorie Name</th>
                  <th className="px-6 py-4">Deals/Items</th>
                  <th className="px-6 py-4 text-center">Status</th>
                  <th className="px-6 py-4 text-center">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-zinc-100 underline decoration-zinc-100 italic">
                {activeTab === "Categories" && categories.length > 0 && categories.map((cat) => (
                  <tr key={cat.id} className="hover:bg-zinc-50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <span className="w-10 h-10 flex items-center justify-center bg-zinc-100 rounded-lg text-lg grayscale group-hover:grayscale-0 transition-all">
                          {categoryIcons[cat.name] || "📦"}
                        </span>
                        <span className="text-sm font-black text-zinc-900">{cat.name}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-sm text-zinc-900 font-black">{cat.items || 0} items</td>
                    <td className="px-6 py-4 text-center">
                      <span className="px-3 py-1 bg-[#10B981] text-white text-[10px] font-black uppercase rounded leading-none">Active</span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center justify-center gap-3">
                        <button className="p-2 text-zinc-400 hover:text-orange-500 transition-colors active:scale-95"><Edit size={18} /></button>
                        <button onClick={() => handleDelete("Categories", cat.id, cat.name)} className="p-2 text-zinc-400 hover:text-red-500 transition-colors active:scale-95"><Trash2 size={18} /></button>
                      </div>
                    </td>
                  </tr>
                ))}

                {activeTab === "Categories" && categories.length === 0 && (
                  <tr>
                    <td colSpan={4} className="px-6 py-20 text-center text-zinc-400 font-bold italic">No categories found in backend.</td>
                  </tr>
                )}

                {activeTab === "Tags" && (
                  <tr>
                    <td colSpan={3} className="px-6 py-20 text-center text-zinc-400 font-medium">No tags found.</td>
                  </tr>
                )}

                {activeTab === "Merchants" && merchants.map((mer) => (
                  <tr key={mer.id} className="hover:bg-zinc-50 transition-colors group italic">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 flex items-center justify-center bg-zinc-100 border border-zinc-200 rounded-lg text-xs font-black text-zinc-400 overflow-hidden">{(mer.name || "V").slice(0, 2)}</div>
                        <span className="text-sm font-black text-zinc-900">{mer.name}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-sm text-zinc-900 font-black">N/A</td>
                    <td className="px-6 py-4 text-center">
                      <span className="px-2.5 py-1 text-white text-[10px] font-black uppercase rounded leading-none bg-[#10B981]">
                        Active
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center justify-center gap-2">
                        <button className="p-2 text-zinc-400 hover:text-orange-500 transition-colors active:scale-95"><Edit size={18} /></button>
                        <button onClick={() => handleDelete("Merchants", mer.id, mer.name)} className="p-2 text-zinc-400 hover:text-red-500 transition-colors active:scale-95"><Trash2 size={18} /></button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      <AddTaxonomyModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        type={activeTab.slice(0, -1).toLowerCase() as any} 
      />
    </div>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import { Search, Loader2, Store, CheckCircle, XCircle, Clock, Trash2 } from "lucide-react";
import { getAdminVendors, updateAdminVendorStatus, deleteAdminVendor } from "@/lib/api";
import { useNotification } from "@/context/NotificationContext";

interface Vendor {
  id: number;
  name: string;
  email: string;
  phone: string | null;
  status: "pending" | "active" | "rejected";
  businessName: string | null;
  createdAt: string;
}

export default function VendorsManagement() {
  const { showNotification } = useNotification();
  const [vendors, setVendors] = useState<Vendor[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");

  const fetchVendors = async () => {
    try {
      setLoading(true);
      const res = await getAdminVendors();
      if (res.success && res.data) {
        setVendors(res.data);
      }
    } catch (err) {
      showNotification("error", "Failed to load vendors");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchVendors();
  }, []);

  const handleUpdateStatus = async (id: number, status: "active" | "rejected") => {
    try {
      await updateAdminVendorStatus(id, status);
      showNotification("success", `Vendor marked as ${status}`);
      fetchVendors();
    } catch (err: any) {
      showNotification("error", err.message || "Failed to update vendor status");
    }
  };

  const handleDelete = async (id: number, name: string) => {
    if (!window.confirm(`Are you absolutely sure you want to permanently delete the vendor "${name}" and all of their deals/products? This action cannot be undone.`)) {
      return;
    }

    try {
      await deleteAdminVendor(id);
      showNotification("success", "Vendor and associated deals deleted successfully");
      fetchVendors();
    } catch (err: any) {
      showNotification("error", err.message || "Failed to delete vendor");
    }
  };

  const filteredVendors = vendors.filter(
    (v) =>
      v.name.toLowerCase().includes(search.toLowerCase()) ||
      v.email.toLowerCase().includes(search.toLowerCase()) ||
      (v.businessName && v.businessName.toLowerCase().includes(search.toLowerCase()))
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-zinc-900">Vendors Management</h1>
          <p className="text-zinc-500">Approve, reject, or suspend vendor accounts</p>
        </div>
      </div>

      {/* Search Bar */}
      <div className="bg-white p-4 rounded-xl border border-zinc-200 shadow-sm flex items-center gap-3">
        <Search className="text-zinc-400" size={20} />
        <input
          type="text"
          placeholder="Search by name, email, or business name..."
          className="flex-1 outline-none text-sm bg-transparent"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-zinc-200 overflow-hidden">
        {loading ? (
          <div className="flex justify-center items-center p-20">
            <Loader2 className="animate-spin text-orange-500" size={32} />
          </div>
        ) : filteredVendors.length === 0 ? (
          <div className="p-12 text-center text-zinc-500">
            <Store size={48} className="mx-auto text-zinc-300 mb-4" />
            <p className="font-medium text-lg text-zinc-900">No vendors found</p>
            <p>No vendor applications match your search.</p>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm border-collapse">
              <thead>
                <tr className="border-b border-zinc-200 bg-zinc-50/50">
                  <th className="p-4 font-semibold text-zinc-600">Business/Owner</th>
                  <th className="p-4 font-semibold text-zinc-600">Contact</th>
                  <th className="p-4 font-semibold text-zinc-600">Registered</th>
                  <th className="p-4 font-semibold text-zinc-600">Status</th>
                  <th className="p-4 font-semibold text-zinc-600 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-zinc-100">
                {filteredVendors.map((vendor) => (
                  <tr key={vendor.id} className="hover:bg-zinc-50/50 transition-colors">
                    <td className="p-4">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-lg bg-orange-100 flex items-center justify-center text-orange-600 font-bold">
                          {vendor.businessName ? vendor.businessName[0].toUpperCase() : vendor.name[0].toUpperCase()}
                        </div>
                        <div>
                          <div className="font-bold text-zinc-900">{vendor.businessName || "No Business Name"}</div>
                          <div className="text-zinc-500 hidden sm:block">{vendor.name}</div>
                        </div>
                      </div>
                    </td>
                    <td className="p-4">
                      <div className="text-zinc-900">{vendor.email}</div>
                      <div className="text-zinc-500 text-xs mt-0.5">{vendor.phone || "No phone"}</div>
                    </td>
                    <td className="p-4 text-zinc-600">
                      {new Date(vendor.createdAt).toLocaleDateString()}
                    </td>
                    <td className="p-4">
                      {vendor.status === "pending" && (
                        <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-semibold bg-amber-50 text-amber-700 border border-amber-200">
                          <Clock size={12} /> Pending
                        </span>
                      )}
                      {vendor.status === "active" && (
                        <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-semibold bg-emerald-50 text-emerald-700 border border-emerald-200">
                          <CheckCircle size={12} /> Active
                        </span>
                      )}
                      {vendor.status === "rejected" && (
                        <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-semibold bg-red-50 text-red-700 border border-red-200">
                          <XCircle size={12} /> Rejected
                        </span>
                      )}
                    </td>
                    <td className="p-4 text-right flex items-center justify-end gap-2">
                      {vendor.status === "pending" || vendor.status === "rejected" ? (
                        <button
                          onClick={() => handleUpdateStatus(vendor.id, "active")}
                          className="px-3 py-1.5 bg-emerald-50 text-emerald-600 font-medium rounded-lg text-xs hover:bg-emerald-100 transition border border-emerald-200"
                        >
                          Approve
                        </button>
                      ) : (
                        <button
                          onClick={() => handleUpdateStatus(vendor.id, "rejected")}
                          className="px-3 py-1.5 bg-red-50 text-red-600 font-medium rounded-lg text-xs hover:bg-red-100 transition border border-red-200"
                        >
                          Suspend
                        </button>
                      )}

                      {vendor.status === "pending" && (
                        <button
                          onClick={() => handleUpdateStatus(vendor.id, "rejected")}
                          className="px-3 py-1.5 bg-red-50 text-red-600 font-medium rounded-lg text-xs hover:bg-red-100 transition border border-red-200"
                        >
                          Reject
                        </button>
                      )}

                      <button
                        onClick={() => handleDelete(vendor.id, vendor.name)}
                        className="p-1.5 bg-red-50 text-red-600 rounded-lg hover:bg-red-100 transition border border-red-200"
                        title="Delete Vendor"
                      >
                        <Trash2 size={16} />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

