"use client";

import React, { useEffect, useState } from "react";
import { Eye, Plus, Search } from "lucide-react";
import { API_BASE } from "@/services/apiClient";

type TeamStatus = "Online" | "Offline";
type PerformanceState = "On track" | "At risk" | "Below target";

export default function TeamPage() {
  const [members, setMembers] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function loadTeam() {
      try {
        const res = await fetch(`${API_BASE}/users?role=vendor`);
        const data = await res.json();
        if (data.success) {
          setMembers(data.data);
        }
      } catch (err) {
        console.error("Failed to load team", err);
      } finally {
        setLoading(false);
      }
    }
    loadTeam();
  }, []);

  if (loading) return <div className="p-20 text-center font-bold text-orange-600 text-2xl">Loading team...</div>;

  const onlineCount = members.filter(m => m.status === "Online").length;

  return (
    <div className="space-y-10 animate-in fade-in duration-600">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-bold text-zinc-900 mb-2">My Team</h1>
          <div className="flex items-center gap-3">
             <span className="text-zinc-500 font-bold text-sm">{members.length} total</span>
             <span className="w-1.5 h-1.5 rounded-full bg-zinc-300"></span>
             <span className="text-emerald-600 font-bold text-sm">{onlineCount} Online</span>
          </div>
        </div>
        <button className="flex items-center gap-3 bg-[#F05023] hover:bg-[#D44D1F] text-white font-bold py-4 px-10 rounded-xl transition-all shadow-lg shadow-orange-100">
          <Plus size={20} />
          Add Marketer
        </button>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-2 gap-8">
        {members.map((member) => (
          <div key={member.id} className="bg-white rounded-2xl border border-zinc-200 shadow-sm overflow-hidden p-8 hover:shadow-md transition-shadow relative group">
            <div className="flex justify-between items-start mb-8">
              <div className="flex items-center gap-6">
                <div className="relative">
                  <div className="w-16 h-16 rounded-full bg-zinc-100 flex items-center justify-center text-xl font-black text-zinc-900 border-2 border-zinc-50">
                    {member.name.slice(0, 1)}
                    <div className={`absolute bottom-0 right-0 w-4 h-4 rounded-full border-4 border-white ${member.status === "Online" ? "bg-emerald-500" : "bg-zinc-300"}`}></div>
                  </div>
                </div>
                <div>
                  <h3 className="text-xl font-black text-zinc-900 mb-1">{member.name}</h3>
                  <p className="text-zinc-500 font-bold text-sm mb-2">{member.email}</p>
                  <span className={`text-[10px] font-black uppercase tracking-widest ${member.status === "Online" ? "text-emerald-600" : "text-zinc-400"}`}>
                    {member.status}
                  </span>
                </div>
              </div>
              <div className={`px-4 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-wider ${
                member.perf === "On track" ? "bg-emerald-50 text-emerald-600" : 
                member.perf === "At risk" ? "bg-orange-50 text-orange-600" : "bg-red-50 text-red-600"
              }`}>
                {member.perf}
              </div>
            </div>

            <div className="grid grid-cols-3 gap-4 bg-zinc-50/50 rounded-2xl p-6 mb-8 border border-zinc-100/50">
              <div className="text-center border-r border-zinc-200/50">
                <span className="text-[10px] font-black text-zinc-400 uppercase tracking-widest block mb-2 text-center">Today</span>
                <span className="text-2xl font-black text-zinc-900">0</span>
              </div>
              <div className="text-center border-r border-zinc-200/50">
                <span className="text-[10px] font-black text-zinc-400 uppercase tracking-widest block mb-2 text-center">Week</span>
                <span className="text-2xl font-black text-zinc-900">0</span>
              </div>
              <div className="text-center">
                <span className="text-[10px] font-black text-zinc-400 uppercase tracking-widest block mb-2 text-center">Ads</span>
                <span className="text-2xl font-black text-zinc-900">{member.total_ads}</span>
              </div>
            </div>

            <div className="relative h-1.5 w-full bg-zinc-100 rounded-full overflow-hidden mb-8">
              <div className="absolute top-0 left-0 h-full bg-[#F05023] rounded-full" style={{ width: `${Math.min((member.total_ads / 50) * 100, 100)}%` }}></div>
            </div>

            <button className="w-full flex items-center justify-center gap-2 py-2 text-zinc-400 font-bold text-sm hover:text-[#F05023] transition-colors">
              <Eye size={16} />
              Tap to view & manage
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}

"use client";

import React, { useEffect, useState } from "react";
import { Plus, Search, Filter, Download } from "lucide-react";
import { API_BASE } from "@/services/apiClient";

type VendorStatus = "Paid" | "Unpaid";

export default function VendorsPage() {
  const [vendors, setVendors] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<"All" | "Paid" | "Unpaid">("All");
  const [search, setSearch] = useState("");

  useEffect(() => {
    async function loadVendors() {
      try {
        const res = await fetch(`${API_BASE}/users?role=vendor`);
        const data = await res.json();
        if (data.success) {
          // Map backend users to vendor display format
          const mapped = data.data.map((u: any) => ({
            id: u.id,
            business: u.name || "Unknown Business",
            type: "General", // Default as not in schema
            location: "Nigeria", // Default
            marketer: "Admin", // Default
            status: "Paid" as VendorStatus, // Default
            email: u.email
          }));
          setVendors(mapped);
        }
      } catch (err) {
        console.error("Failed to load vendors", err);
      } finally {
        setLoading(false);
      }
    }
    loadVendors();
  }, []);

  const filteredVendors = vendors.filter(v => {
    const matchesFilter = filter === "All" || v.status === filter;
    const matchesSearch = v.business.toLowerCase().includes(search.toLowerCase()) || 
                          v.marketer.toLowerCase().includes(search.toLowerCase()) ||
                          v.email.toLowerCase().includes(search.toLowerCase());
    return matchesFilter && matchesSearch;
  });

  if (loading) return <div className="p-20 text-center font-bold text-orange-600 text-2xl">Loading vendors...</div>;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h1 className="text-3xl font-bold text-zinc-900 mb-2">Vendors Management</h1>
          <p className="text-zinc-500 font-medium">Manage and monitor all onboarded vendors</p>
        </div>
        <button className="flex items-center gap-3 bg-[#F05023] hover:bg-[#D44D1F] text-white font-bold py-3.5 px-8 rounded-xl transition-all shadow-lg shadow-orange-100">
          <Plus size={20} />
          Add Vendor
        </button>
      </div>

      <div className="bg-white rounded-2xl border border-zinc-200 shadow-sm overflow-hidden p-8">
        {/* Toolbar */}
        <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6 mb-10 pb-8 border-b border-zinc-100">
          <div className="flex p-1 bg-[#F9FAFB] rounded-xl w-fit border border-zinc-200">
            {(["All", "Paid", "Unpaid"] as const).map((t) => (
              <button
                key={t}
                onClick={() => setFilter(t)}
                className={`px-8 py-2.5 rounded-lg text-sm font-bold transition-all ${
                  filter === t 
                    ? "bg-white text-zinc-900 shadow-sm" 
                    : "text-zinc-500 hover:text-zinc-700"
                }`}
              >
                {t}
              </button>
            ))}
          </div>

          <div className="flex items-center gap-4">
            <div className="relative flex-1 lg:w-80">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-zinc-400" size={18} />
              <input 
                type="text" 
                placeholder="Search business or marketer..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="w-full pl-12 pr-4 py-3 bg-[#F9FAFB] border border-zinc-200 rounded-xl outline-none focus:border-[#F05023] transition-colors text-sm font-medium"
              />
            </div>
            <button className="p-3 border border-zinc-200 rounded-xl hover:bg-zinc-50 transition-colors">
              <Download size={20} className="text-zinc-600" />
            </button>
          </div>
        </div>

        {/* Table */}
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-[#F9FAFB] border-b border-zinc-200">
                <th className="px-6 py-4 text-zinc-500 font-bold text-xs uppercase tracking-widest">Business Name</th>
                <th className="px-6 py-4 text-zinc-500 font-bold text-xs uppercase tracking-widest">Category</th>
                <th className="px-6 py-4 text-zinc-500 font-bold text-xs uppercase tracking-widest">Location</th>
                <th className="px-6 py-4 text-zinc-500 font-bold text-xs uppercase tracking-widest">Marketer</th>
                <th className="px-6 py-4 text-zinc-500 font-bold text-xs uppercase tracking-widest">Status</th>
                <th className="px-6 py-4 text-zinc-500 font-bold text-xs uppercase tracking-widest text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-zinc-100">
              {filteredVendors.map((vendor) => (
                <tr key={vendor.id} className="group hover:bg-[#F9FAFB] transition-colors">
                  <td className="px-6 py-6">
                    <span className="text-zinc-900 font-bold text-[15px]">{vendor.business}</span>
                  </td>
                  <td className="px-6 py-6">
                    <span className="text-zinc-600 font-medium text-sm bg-zinc-100 px-3 py-1.5 rounded-lg">{vendor.type}</span>
                  </td>
                  <td className="px-6 py-6">
                    <span className="text-zinc-500 font-medium text-sm">{vendor.location}</span>
                  </td>
                  <td className="px-6 py-6">
                    <span className="text-zinc-900 font-bold text-sm">{vendor.marketer}</span>
                  </td>
                  <td className="px-6 py-6">
                    <span className={`px-4 py-1.5 rounded-full text-[11px] font-bold uppercase tracking-wider ${
                      vendor.status === 'Paid' 
                        ? 'bg-[#D1FAE5] text-[#059669]' 
                        : 'bg-[#FEE2E2] text-[#DC2626]'
                    }`}>
                      {vendor.status}
                    </span>
                  </td>
                  <td className="px-6 py-6 text-right">
                    <button className="text-[#F05023] font-bold text-sm hover:underline underline-offset-4 decoration-2">
                      Manage
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {filteredVendors.length === 0 && (
            <div className="py-24 text-center">
              <p className="text-zinc-400 font-black">No vendors found matching your criteria</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

"use client"
import React, { useEffect, useState } from "react"
import Navbar from '../../../../components/Navbar'
import Footer from '../../../../components/Footer'
import Link from 'next/link'
import SimilarItems from '../../../../components/SimilarItems'
import Button from '../../../../components/ui/Button'
import { API_BASE, apiFetch } from "@/services/apiClient"
import { logAdView, logContactView } from "@/services/analytics.service"

type Props = {
  params: Promise<{ id: string }>
}

export default function ProductPage({ params }: Props) {
  // Unwrap params using React.use()
  const { id } = React.use(params);
  const [loading, setLoading] = useState(true)
  const [product, setProduct] = useState<any>({
    id, title: '', desc: '', price: '', sellerId: '', images: ['/assets/images/bgphone.svg'], condition: 'Brand New'
  })
  useEffect(() => {
    let active = true
    ;(async () => {
      try {
        const data = await apiFetch<{ success: boolean; data: any }>(`ads/${id}`);
        if (!active || !data?.success) return
        const d = data.data
        let images = [d.image_url || '/assets/images/bgphone.svg']
        if (d.images_json) {
          try {
            const parsed = typeof d.images_json === 'string' ? JSON.parse(d.images_json) : d.images_json
            if (Array.isArray(parsed) && parsed.length > 0) {
              images = parsed
            }
          } catch (e) {
            console.error("Failed to parse images_json", e)
          }
        }
        const sellerData = await apiFetch<{ success: boolean; data: any }>(`users/${d.userId}`);
        const seller = sellerData?.data || {}
        const sellerName = seller.name || "Seller"
        const createdAt = seller.createdAt ? new Date(seller.createdAt) : new Date();
        const memberSince = createdAt.toLocaleDateString("en-US", { month: "long", year: "numeric" });
        setProduct({
          id: d.id,
          title: d.title,
          desc: d.description || '',
          price: `₦${Number(d.price).toLocaleString()}`,
          sellerId: String(d.userId),
          sellerName,
          sellerRating: seller.rating || 2.9,
          sellerMemberSince: memberSince,
          sellerTotalAds: seller.total_ads || 0,
          sellerResponseTime: seller.responseTime || "Within 1 hour",
          images,
          condition: d.condition || 'Brand New',
          location: d.location || d.city || 'Nigeria',
          brand: d.brand,
          model: d.model,
          color: d.color,
          negotiable: d.negotiable,
          screenSize: d.screenSize,
          ram: d.ram,
          mainCamera: d.mainCamera,
          selfieCamera: d.selfieCamera,
          battery: d.battery,
          internalStorage: d.internalStorage,
          state: d.state,
          city: d.city,
        })
        // log a view
        try { await logAdView(Number(id)); } catch {}
      } catch (err) {
        console.error("Failed to fetch product or seller:", err);
      } finally {
        if (active) setLoading(false)
      }
    })()
    return () => { active = false }
  }, [id])

  const sampleImages: string[] = Array.isArray(product.images)
    ? (product.images as string[])
    : (product.images ? [String(product.images)] : [])
  const [selected, setSelected] = useState(0)
  const [activeTab, setActiveTab] = useState<'description' | 'features' | 'package' | 'specs'>('description')

  const [messageModal, setMessageModal] = useState(false);
  const [messageText, setMessageText] = useState("");
  const [sendingMessage, setSendingMessage] = useState(false);

  const handleSendMessage = async () => {
    if (!messageText.trim()) return;
    try {
      setSendingMessage(true);
      const token = typeof window !== "undefined" ? window.localStorage.getItem("token") : null;
      if (!token) {
        alert("Please login to send a message");
        return;
      }
      const res = await fetch(`${API_BASE}/messages`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({
          to_user_id: Number(product.sellerId),
          deal_id: Number(product.id),
          content: messageText.trim(),
        }),
      });
      const data = await res.json();
      if (data.success) {
        alert("Message sent successfully!");
        setMessageModal(false);
        setMessageText("");
        try { await logContactView(Number(product.id)); } catch {}
      } else {
        alert(data.message || "Failed to send message");
      }
    } catch (err) {
      alert("An error occurred while sending the message");
    } finally {
      setSendingMessage(false);
    }
  };

  return (
    <div>
      <Navbar />
      <main className="max-w-[1200px] mx-auto mt-6 px-4 sm:px-6">
        <nav className="text-gray-600 text-sm mb-4">Home &gt; Phones &gt; Mobile Phones &gt; Smartphones</nav>

        <div className="grid gap-6 items-start lg:grid-cols-[1fr_360px]">
          {/* Left: Gallery + Info (card with orange border) */}
          <section className="rounded-lg border-2 border-orange-300 bg-white p-4 sm:p-6">
            <div className="flex items-start justify-between mb-4">
              <div>
                <h1 className="text-2xl font-extrabold text-orange-600">{product.title || (loading ? "Loading..." : "Ad")}</h1>
                <p className="text-gray-700 mt-2">{product.desc}</p>
              </div>
              <div className="flex items-center gap-3">
                <button className="w-9 h-9 rounded-md border border-gray-200 flex items-center justify-center">♡</button>
                <button className="w-9 h-9 rounded-md border border-gray-200 flex items-center justify-center">⤴</button>
              </div>
            </div>

            <div className="relative">
              <div className="w-full h-[320px] sm:h-[420px] md:h-[480px] lg:h-[520px] rounded-md overflow-hidden border border-orange-200">
                <img src={sampleImages[selected]} alt={product.title || 'image'} className="w-full h-full object-cover block" />
              </div>

              {/* Left/Right arrows */}
              <button
                aria-label="previous image"
                type="button"
                onClick={() => setSelected((prev) => (prev - 1 + sampleImages.length) % sampleImages.length)}
                className="hidden sm:flex absolute left-3 top-1/2 -translate-y-1/2 w-10 h-10 rounded-full bg-white/80 border border-gray-200 items-center justify-center"
              >
                ‹
              </button>
              <button
                aria-label="next image"
                type="button"
                onClick={() => setSelected((prev) => (prev + 1) % sampleImages.length)}
                className="hidden sm:flex absolute right-3 top-1/2 -translate-y-1/2 w-10 h-10 rounded-full bg-white/80 border border-gray-200 items-center justify-center"
              >
                ›
              </button>

              <div className="absolute bottom-4 right-6">
                <span className="bg-orange-600 text-white px-3 py-1 rounded-full text-sm">View Image</span>
              </div>
            </div>

            <div className="mt-4 flex items-center gap-3 overflow-x-auto">
              {sampleImages.map((src: string, i: number) => (
                <button
                  key={`${src}-${i}`}
                  onClick={() => setSelected(i)}
                  type="button"
                  className={`flex-shrink-0 w-14 h-10 sm:w-20 sm:h-14 rounded overflow-hidden border ${i === selected ? 'border-orange-500' : 'border-gray-200'} p-0`}
                  aria-label={`thumbnail-${i}`}
                >
                  <img src={src} className="w-full h-full object-cover" alt={`${product.title} thumbnail ${i + 1}`} />
                </button>
              ))}
            </div>
          </section>

          {/* Right: Price box + Seller Info */}
          <aside className="space-y-4">
            <div className="rounded-lg bg-white border border-orange-200 p-6 shadow-sm relative lg:sticky lg:top-24">
              <div className="absolute top-4 right-4">
                <span className="bg-green-100 text-green-700 px-3 py-1 rounded-full text-xs">{product.condition}</span>
              </div>

              <div className="text-3xl font-extrabold text-orange-600">{product.price}</div>
              <div className="mt-2 inline-block bg-gray-100 text-gray-600 px-3 py-1 rounded text-sm">Negotiable</div>

              <div className="mt-6 space-y-3">
                <Button 
                  onClick={() => {
                    const token = typeof window !== "undefined" ? window.localStorage.getItem("token") : null;
                    if (!token) { alert("Please login to contact seller"); return; }
                    setMessageText("I'm interested in your ad.");
                    setMessageModal(true);
                  }} 
                  className="w-full bg-orange-600 text-white py-3"
                >
                  📞 Contact Seller
                </Button>
                <Button 
                  onClick={() => {
                    const token = typeof window !== "undefined" ? window.localStorage.getItem("token") : null;
                    if (!token) { alert("Please login to chat"); return; }
                    setMessageText("Hello! I would like to chat about this item.");
                    setMessageModal(true);
                  }} 
                  className="w-full bg-orange-600 text-white py-3"
                >
                  💬 Chat Seller
                </Button>
              </div>
            </div>

            <div className="rounded-lg bg-white border border-orange-200 p-4">
              <div className="flex items-center justify-between mb-3">
                <h3 className="font-semibold">Seller Information</h3>
                <div className="text-xs text-gray-500">● Last seen 12:01 PM</div>
              </div>

              <div className="border-t border-b border-gray-100 py-3">
                <div className="flex items-center gap-3 mb-3">
                    <div className="w-10 h-10 rounded-full bg-orange-500 text-white flex items-center justify-center font-bold">{(product.sellerName || 'S').slice(0,1)}</div>
                    <div>
                      <div className="font-semibold">
                        <Link href={`/seller/${product.sellerId}`} className="hover:underline text-orange-600">{product.sellerName || 'Seller'}</Link> <span className="text-green-600">✔</span>
                      </div>
                      <div className="text-yellow-400">
                        {Array.from({ length: 5 }).map((_, i) => (
                          <span key={i}>{i < Math.floor(product.sellerRating || 0) ? "⭐️" : "☆"}</span>
                        ))}
                      </div>
                      <div className="mt-2">
                        <Link href={`/seller/${product.sellerId}`} className="text-sm text-orange-500 font-medium">View Seller Profile</Link>
                      </div>
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-2 text-sm text-gray-700">
                  <div>Member Since:</div><div className="font-medium">{product.sellerMemberSince || "January 2023"}</div>
                  <div>Total Ads Posted:</div><div className="font-medium">{product.sellerTotalAds || 0} items</div>
                  <div>Response Time:</div><div className="font-medium">{product.sellerResponseTime || "Within 1 hour"}</div>
                  <div>Customer Rating:</div><div className="font-medium">{(product.sellerRating || 2.9).toFixed(1)}/5.0</div>
                </div>
              </div>

              <div className="mt-4 space-y-2">
                <Link href={`/seller/${product.sellerId}`} className="w-full inline-block text-center bg-orange-600 text-white py-2 rounded">🔎 View Seller Profile</Link>
                <Link href={`/seller/${product.sellerId}`} className="w-full inline-block text-center bg-orange-600 text-white py-2 rounded">📋 See All Ads from Seller</Link>
              </div>
            </div>
          </aside>
        </div>
        
        {/* Message Modal */}
        {messageModal && (
          <div className="fixed inset-0 bg-black/50 z-[100] flex items-center justify-center p-4">
            <div className="bg-white rounded-xl w-full max-w-md p-6 shadow-2xl">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-bold text-gray-900">Message to {product.sellerName}</h3>
                <button onClick={() => setMessageModal(false)} className="text-gray-400 hover:text-gray-600">✕</button>
              </div>
              <textarea
                value={messageText}
                onChange={(e) => setMessageText(e.target.value)}
                placeholder="Type your message here..."
                className="w-full h-32 border border-gray-200 rounded-lg p-3 text-sm focus:ring-2 focus:ring-orange-500 focus:border-transparent outline-none resize-none"
              />
              <div className="mt-4 flex gap-3">
                <button
                  onClick={() => setMessageModal(false)}
                  className="flex-1 py-3 border border-gray-200 rounded-lg font-semibold text-gray-700 hover:bg-gray-50 transition"
                >
                  Cancel
                </button>
                <button
                  disabled={sendingMessage || !messageText.trim()}
                  onClick={handleSendMessage}
                  className="flex-1 py-3 bg-orange-600 text-white rounded-lg font-semibold hover:bg-orange-700 transition disabled:opacity-50"
                >
                  {sendingMessage ? "Sending..." : "Send Message"}
                </button>
              </div>
            </div>
          </div>
        )}

        {/* Second row: Description tabs + Reviews and Right column contact options */}
        <div className="grid gap-6 mt-6 lg:grid-cols-[1fr_360px]">
          <div>
            <div className="rounded-lg border border-orange-200 bg-white p-4">
              <div className="border-b pb-3">
                <div className="sm:hidden">
                  <label className="sr-only">Select section</label>
                  <select
                    value={activeTab}
                    onChange={(e) => setActiveTab(e.target.value as any)}
                    className="w-full rounded-md border-gray-200 bg-white px-3 py-2 text-sm"
                  >
                    <option value="description">PRODUCT DESCRIPTION</option>
                    <option value="features">KEY FEATURES</option>
                    <option value="package">PACKAGE CONTENT</option>
                    <option value="specs">SPECIFICATIONS</option>
                  </select>
                </div>

                <div className="hidden sm:flex gap-6">
                  <button
                    onClick={() => setActiveTab('description')}
                    className={`pb-2 font-semibold whitespace-nowrap ${activeTab === 'description' ? 'text-orange-600 border-b-2 border-orange-600' : 'text-gray-800'}`}
                  >
                    PRODUCT DESCRIPTION
                  </button>

                  <button
                    onClick={() => setActiveTab('features')}
                    className={`pb-2 font-semibold whitespace-nowrap ${activeTab === 'features' ? 'text-orange-600 border-b-2 border-orange-600' : 'text-gray-800'}`}
                  >
                    KEY FEATURES
                  </button>

                  <button
                    onClick={() => setActiveTab('package')}
                    className={`pb-2 font-semibold whitespace-nowrap ${activeTab === 'package' ? 'text-orange-600 border-b-2 border-orange-600' : 'text-gray-800'}`}
                  >
                    PACKAGE CONTENT
                  </button>

                  <button
                    onClick={() => setActiveTab('specs')}
                    className={`pb-2 font-semibold whitespace-nowrap ${activeTab === 'specs' ? 'text-orange-600 border-b-2 border-orange-600' : 'text-gray-800'}`}
                  >
                    SPECIFICATIONS
                  </button>
                </div>
              </div>

              <div className="mt-4 text-gray-800 leading-relaxed">
                {activeTab === 'description' && (
                  <div className="whitespace-pre-wrap">
                    {product.desc || "No description provided."}
                  </div>
                )}

                {activeTab === 'features' && (
                  <div className="text-gray-500 italic">No features listed for this item.</div>
                )}

                {activeTab === 'package' && (
                  <div className="text-gray-500 italic">No package content information available.</div>
                )}

                {activeTab === 'specs' && (
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    {product.brand && (
                      <div className="flex justify-between border-b border-gray-100 pb-2">
                        <span className="text-gray-500">Brand</span>
                        <span className="font-semibold">{product.brand}</span>
                      </div>
                    )}
                    {product.model && (
                      <div className="flex justify-between border-b border-gray-100 pb-2">
                        <span className="text-gray-500">Model</span>
                        <span className="font-semibold">{product.model}</span>
                      </div>
                    )}
                    {product.condition && (
                      <div className="flex justify-between border-b border-gray-100 pb-2">
                        <span className="text-gray-500">Condition</span>
                        <span className="font-semibold">{product.condition}</span>
                      </div>
                    )}
                    {product.color && (
                      <div className="flex justify-between border-b border-gray-100 pb-2">
                        <span className="text-gray-500">Color</span>
                        <span className="font-semibold">{product.color}</span>
                      </div>
                    )}
                    {product.screenSize && (
                      <div className="flex justify-between border-b border-gray-100 pb-2">
                        <span className="text-gray-500">Screen Size</span>
                        <span className="font-semibold">{product.screenSize}</span>
                      </div>
                    )}
