export default function SignupPage() {
  const router = useRouter();
  const [role, setRole] = useState<UserRole>("user");
  const [method, setMethod] = useState<ContactMethod>("email");
  const [showPassword, setShowPassword] = useState(false);
  const [formData, setFormData] = useState({
    name: "",
    contact: "",
    password: "",
    confirmPassword: "",
    // vendor-only
    businessName: "",
    businessCategory: "",
    businessAddress: "",
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");

    if (formData.password !== formData.confirmPassword) {
      setError("Passwords do not match");
      return;
    }

    setLoading(true);

    try {
      if (method !== "email") {
        setError("Please select Email and provide a valid email address");
        setLoading(false);
        return;
      }
      const email = formData.contact.trim().toLowerCase();
      await registerUser({
        name: formData.name,
        email,
        password: formData.password.trim(),
        role,
        businessName: formData.businessName,
        businessCategory: formData.businessCategory,
        businessAddress: formData.businessAddress,
      });
      const res = await loginUser({ email, password: formData.password.trim() });
      const r = String(res.user?.role || "").toLowerCase();
      if (r === "vendor") {
        router.push("/vendor-dashboard");
      } else if (r === "admin") {
        router.push("/admin-dashboard");
      } else {
        router.push("/");
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 flex items-center justify-center py-0 px-0 sm:py-12 sm:px-4">
      <div className="w-full sm:max-w-4xl sm:rounded-2xl overflow-hidden shadow-none sm:shadow-2xl border-0 sm:border sm:border-gray-200 bg-white relative">

