"use client";
import { useEffect, useState } from "react";
import { listThreads, getThread, sendMessage, Thread } from "@/services/messages.service";

export default function MessagesPage() {
  const [threads, setThreads] = useState<Thread[]>([]);
  const [active, setActive] = useState<{ userId: number; dealId?: number; otherName?: string } | null>(null);
  const [messages, setMessages] = useState<any[]>([]);
  const [input, setInput] = useState("");
  const [currentUserId, setCurrentUserId] = useState<number | null>(null);

  useEffect(() => {
    if (typeof window !== "undefined") {
      const stored = window.localStorage.getItem("user_id");
      if (stored) setCurrentUserId(Number(stored));
    }
  }, []);

  async function loadThreads() {
    const res = await listThreads();
    const threadsData = res.data || [];
    setThreads(threadsData);
    if (!active && threadsData.length) {
      setActive({ 
        userId: threadsData[0].other_id, 
        dealId: threadsData[0].deal_id || undefined,
        otherName: threadsData[0].other_name
      });
    }
  }

  async function loadThread() {
    if (!active) return;
    const res = await getThread(active.userId, active.dealId);
    setMessages(res.data || []);
  }

  useEffect(() => { loadThreads(); }, []);
  useEffect(() => { 
    if (active) {
      loadThread();
      const interval = setInterval(loadThread, 5000); // Poll every 5 seconds
      return () => clearInterval(interval);
    }
  }, [active?.userId, active?.dealId]);

  async function onSend() {
    if (!input.trim() || !active) return;
    const msg = input.trim();
    setInput("");
    try {
      await sendMessage(active.userId, msg, active.dealId);
      await loadThread();
      await loadThreads();
    } catch (err) {
      alert("Failed to send message");
      setInput(msg);
    }
  }

  return (
    <div className="bg-white rounded-lg border border-zinc-200 shadow-sm overflow-hidden h-[80vh] flex flex-col">
      <div className="flex-1 grid grid-cols-1 md:grid-cols-[300px_1fr] overflow-hidden">
        <aside className="border-r flex flex-col overflow-hidden">
          <div className="p-4 border-b">
            <h2 className="text-xl font-bold text-gray-900">Messages</h2>
          </div>
          <div className="flex-1 overflow-y-auto p-2 space-y-1">
            {threads.map(t => (
              <button
                key={`${t.other_id}-${t.deal_id || 0}`}
                onClick={() => setActive({ 
                  userId: t.other_id, 
                  dealId: t.deal_id || undefined,
                  otherName: t.other_name 
                })}
                className={`w-full text-left p-3 rounded-lg transition-all ${
                  active?.userId === t.other_id && active?.dealId === (t.deal_id || undefined)
                    ? "bg-orange-50 border-orange-200 ring-1 ring-orange-200" 
                    : "hover:bg-gray-50 border-transparent"
                } border`}
              >
                <div className="flex items-center justify-between mb-1">
                  <div className="font-bold text-gray-900 truncate flex-1">
                    {t.other_name || `User #${t.other_id}`}
                  </div>
                  {t.unread_count > 0 && (
                    <span className="ml-2 bg-orange-600 text-white text-[10px] font-bold rounded-full h-5 w-5 flex items-center justify-center shrink-0">
                      {t.unread_count}
                    </span>
                  )}
                </div>
                {t.deal_title && (
                  <div className="text-[10px] text-orange-600 font-bold mb-1 truncate uppercase tracking-wider">
                    Item: {t.deal_title}
                  </div>
                )}
                <div className="text-xs text-gray-500 truncate">{t.last_content}</div>
                <div className="text-[9px] text-gray-400 mt-1">
                  {new Date(t.last_created_at).toLocaleDateString()}
                </div>
              </button>
            ))}
            {threads.length === 0 && (
              <div className="text-center py-10">
                <div className="text-4xl mb-2">💬</div>
                <div className="text-sm text-gray-500 font-medium">No messages yet</div>
              </div>
            )}
          </div>
        </aside>

        <section className="flex flex-col overflow-hidden bg-gray-50">
          {active ? (
            <>
              <div className="p-4 bg-white border-b flex items-center justify-between shadow-sm z-10">
                <div>
                  <h3 className="font-bold text-gray-900">{active.otherName || `User #${active.userId}`}</h3>
                  {active.dealId && (
                    <div className="text-xs text-orange-600 font-medium">Chatting about Ad #{active.dealId}</div>
                  )}
                </div>
              </div>

              <div className="flex-1 overflow-y-auto p-4 space-y-4 flex flex-col">
                {messages.map((m, idx) => {
                  const isMe = m.from_user_id === currentUserId;
                  return (
                    <div key={m.id || idx} className={`flex ${isMe ? "justify-end" : "justify-start"}`}>
                      <div className={`max-w-[80%] rounded-2xl px-4 py-2.5 shadow-sm ${
                        isMe 
                          ? "bg-orange-600 text-white rounded-tr-none" 
                          : "bg-white text-gray-800 rounded-tl-none border border-gray-100"
                      }`}>
                        <div className="text-sm leading-relaxed">{m.content}</div>
                        <div className={`text-[9px] mt-1.5 font-medium ${isMe ? "text-orange-100" : "text-gray-400"}`}>
                          {new Date(m.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                        </div>
                      </div>
                    </div>
                  );
                })}
                {messages.length === 0 && (
                  <div className="flex-1 flex items-center justify-center text-gray-400 text-sm italic">
                    Start a conversation...
                  </div>
                )}
              </div>

              <div className="p-4 bg-white border-t">
                <form 
                  onSubmit={(e) => { e.preventDefault(); onSend(); }}
                  className="flex gap-2"
                >
                  <input 
                    value={input} 
                    onChange={(e) => setInput(e.target.value)} 
                    placeholder="Type your message..." 
                    className="flex-1 border border-gray-200 rounded-xl px-4 py-2.5 text-sm focus:ring-2 focus:ring-orange-500 focus:border-transparent outline-none transition" 
                  />
                  <button 
                    type="submit"
                    disabled={!input.trim()}
                    className="bg-orange-600 hover:bg-orange-700 disabled:opacity-50 text-white px-6 py-2.5 rounded-xl font-bold text-sm transition shadow-md active:scale-95"
                  >
                    Send
                  </button>
                </form>
              </div>
            </>
          ) : (
            <div className="flex-1 flex items-center justify-center text-gray-400 flex-col">
              <div className="text-6xl mb-4">✉️</div>
              <p className="text-lg font-medium">Select a conversation to start chatting</p>
            </div>
          )}
        </section>
      </div>
    </div>
  );
}

"use client";
import React, { useEffect, useState } from "react";
import Navbar from "@/components/Navbar";
import Footer from "@/components/Footer";
import DashboardSidebar from "@/components/dashboard/DashboardSidebar";
import StatsCard from "@/components/dashboard/StatsCard";
import QuickActions from "@/components/dashboard/QuickActions";
import RecentActivity from "@/components/dashboard/RecentActivity";
import {
    Package,
    Eye,
    TrendingUp,
    MessageSquare
} from "lucide-react";
import { getVendorStats } from "@/services/vendor.service";
import { listMyAds } from "@/services/ads.service";

export default function VendorDashboardPage() {
    const [stats, setStats] = useState<{ads:number; views:number; sold:number; msgs:number; unread:number}>({ads:0, views:0, sold:0, msgs:0, unread:0});
    const [recentAds, setRecentAds] = useState<any[]>([]);

    useEffect(() => {
        (async () => {
            try {
                const res = await getVendorStats();
                const d = res.data;
                setStats({ ads: d.total_ads, views: d.total_views, sold: d.items_sold, msgs: d.messages_total, unread: d.messages_unread });
                
                const adsRes = await listMyAds();
                if (adsRes.success) {
                    setRecentAds(adsRes.data.slice(0, 5));
                }
            } catch {}
        })();
    }, []);
    return (
        <>
            <div className="mb-8 lg:mb-12">
                <h1 className="text-[#FF6B35] text-3xl sm:text-4xl lg:text-5xl font-black mb-2">
                    Vendor Dashboard
                </h1>
                <p className="text-zinc-600 font-semibold text-sm lg:text-base">
                    Manage your listings and track performance
                </p>
            </div>

            {/* Stats Grid */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
                <StatsCard
                    label="Total Ads"
                    value={stats.ads}
                    subtext="this month"
                    
                    icon={Package}
                />
                <StatsCard
                    label="Total Views"
                    value={stats.views}
                    subtext="this month"
                   
                    icon={Eye}
                />
                <StatsCard
                    label="Items Sold"
                    value={stats.sold}
                    subtext="this month"
                   
                    icon={TrendingUp}
                />
                <StatsCard
                    label="Messages"
                    value={stats.msgs}
                    subtext={`${stats.unread} unread`}
                    subtextColor="text-zinc-500"
                    
                    icon={MessageSquare}
                />
            </div>

            {/* Quick Actions */}
            <QuickActions />

            {/* Recent Activity */}
            <RecentActivity ads={recentAds} />
        </>
    );
}

"use client";
import React, { useEffect, useRef, useState } from "react";
import Image from "next/image";
import { Camera } from "lucide-react";
import { uploadImage } from "@/services/upload.service";
import { getMyProfile, updateProfileImage } from "@/lib/api";

export default function PersonalDetailsPage() {
    const [profile, setProfile] = useState<any>({
        name: "", email: "", phone: "", businessName: "", businessCategory: "", businessAddress: "", about: ""
    });
    const [photo, setPhoto] = useState<string | null>(null);
    const [saving, setSaving] = useState(false);
    const [message, setMessage] = useState({ text: "", type: "" });
    const inputRef = useRef<HTMLInputElement | null>(null);

    useEffect(() => {
        (async () => {
            try {
                const res = await getMyProfile();
                if (res?.data) {
                    const data = res.data as any;
                    setProfile({
                        name: data.name || "",
                        email: data.email || "",
                        phone: data.phone || "",
                        businessName: data.businessName || "",
                        businessCategory: data.businessCategory || "",
                        businessAddress: data.businessAddress || "",
                        about: data.about || "",
                    });
                    setPhoto(data.profile_image_url || null);
                }
            } catch {}
        })();
    }, []);

    async function onPick(e: React.ChangeEvent<HTMLInputElement>) {
        const f = e.target.files?.[0];
        if (!f) return;
        setSaving(true);
        try {
            const { url } = await uploadImage(f);
            setPhoto(url);
            await updateProfileImage(url);
            if (typeof window !== "undefined") {
                window.localStorage.setItem("profile_image_url", url);
            }
        } catch (err) {
            console.error(err);
        } finally {
            setSaving(false);
        }
    }

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
        setProfile({ ...profile, [e.target.name]: e.target.value });
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setSaving(true);
        setMessage({ text: "", type: "" });
        try {
            // using the new updateMyProfile function imported via api.ts
            // Note: email cannot be changed via this profile update usually, but we keep it readOnly or send it.
            const { updateMyProfile } = require("@/lib/api");
            await updateMyProfile({
                name: profile.name,
                phone: profile.phone,
                businessName: profile.businessName,
                businessCategory: profile.businessCategory,
                businessAddress: profile.businessAddress,
                about: profile.about
            });
            setMessage({ text: "Profile updated successfully!", type: "success" });
        } catch (err: any) {
            setMessage({ text: err.message || "Failed to update profile", type: "error" });
        } finally {
            setSaving(false);
        }
    };

    return (
        <div className="bg-white rounded-lg border border-zinc-200 shadow-[0_2px_15px_-3px_rgba(0,0,0,0.07)] overflow-hidden p-8 lg:p-12 animate-in fade-in duration-500">
            <h2 className="text-black font-black text-2xl mb-8">Personal & Business Details</h2>

            {message.text && (
                <div className={`mb-6 p-4 rounded-lg font-bold text-sm ${message.type === 'success' ? 'bg-emerald-50 text-emerald-600' : 'bg-red-50 text-red-600'}`}>
                    {message.text}
                </div>
            )}

            <div className="max-w-3xl">
                <div className="mb-12 relative inline-block">
                    <div className="w-32 h-32 rounded-full overflow-hidden border-4 border-white shadow-lg relative bg-zinc-100">
                        {photo ? (
                          <img src={photo} alt="Profile" className="absolute inset-0 w-full h-full object-cover" />
                        ) : (
                          <div className="flex items-center justify-center w-full h-full text-zinc-400 font-bold text-3xl">
                              {profile.name ? profile.name.substring(0, 1).toUpperCase() : "?"}
                          </div>
                        )}
                    </div>
                    <label className="absolute bottom-0 right-0 bg-[#E85A28] text-white p-2.5 rounded-full border-4 border-white shadow-md hover:bg-[#D44D1F] transition-all cursor-pointer">
                        <CameraIcon />
                        <input ref={inputRef} type="file" accept="image/*" className="hidden" onChange={onPick} />
                    </label>
                </div>

                <form onSubmit={handleSave} className="space-y-8">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div className="flex flex-col gap-2">
                            <label className="text-black font-black text-[15px]">Full Name</label>
                            <input type="text" name="name" value={profile.name} onChange={handleChange} required className="border border-zinc-200 rounded-lg p-4 text-zinc-900 font-bold focus:outline-none focus:border-[#E85A28] transition-colors" placeholder="Enter full name" />
                        </div>
                        <div className="flex flex-col gap-2">
                            <label className="text-black font-black text-[15px]">Email Address (Read Only)</label>
                            <input type="email" value={profile.email} readOnly className="border border-zinc-200 bg-zinc-50 rounded-lg p-4 text-zinc-500 font-bold focus:outline-none transition-colors cursor-not-allowed" />
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div className="flex flex-col gap-2">
                            <label className="text-black font-black text-[15px]">Phone Number</label>
                            <input type="text" name="phone" value={profile.phone} onChange={handleChange} className="border border-zinc-200 rounded-lg p-4 text-zinc-900 font-bold focus:outline-none focus:border-[#E85A28] transition-colors" placeholder="+234 8100909 000" />
                        </div>
                        <div className="flex flex-col gap-2">
                            <label className="text-black font-black text-[15px]">Business Name</label>
                            <input type="text" name="businessName" value={profile.businessName} onChange={handleChange} className="border border-zinc-200 rounded-lg p-4 text-zinc-900 font-bold focus:outline-none focus:border-[#E85A28] transition-colors" placeholder="e.g. Adaeze Fashion House" />
                        </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                        <div className="flex flex-col gap-2">
                            <label className="text-black font-black text-[15px]">Business Category</label>
                            <div className="relative">
                                <select name="businessCategory" value={profile.businessCategory} onChange={handleChange} className="appearance-none w-full border border-zinc-200 rounded-lg p-4 text-zinc-900 font-bold focus:outline-none focus:border-[#E85A28] transition-colors bg-white">
                                    <option value="">Select a category</option>
                                    <option value="fashion">Fashion & Clothing</option>
                                    <option value="electronics">Electronics & Gadgets</option>
                                    <option value="food">Food & Groceries</option>
                                    <option value="beauty">Beauty & Health</option>
                                    <option value="home">Home & Furniture</option>
                                    <option value="auto">Automobiles & Parts</option>
                                    <option value="services">Services</option>
                                    <option value="other">Other</option>
                                </select>
                                <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-zinc-500">
                                    <ChevronDownIcon />
                                </div>
                            </div>
                        </div>
                        <div className="flex flex-col gap-2">
                            <label className="text-black font-black text-[15px]">Business Address</label>
                            <input type="text" name="businessAddress" value={profile.businessAddress} onChange={handleChange} className="border border-zinc-200 rounded-lg p-4 text-zinc-900 font-bold focus:outline-none focus:border-[#E85A28] transition-colors" placeholder="e.g. 14 Broad Street, Lagos" />
                        </div>
                    </div>

                    <div className="flex flex-col gap-2">
                        <label className="text-black font-black text-[15px]">About Your Business</label>
                        <textarea
                            name="about"
                            value={profile.about}
                            onChange={handleChange}
                            rows={4}
                            placeholder="Write a short description about yourself or your business"
                            className="border border-zinc-200 rounded-lg p-4 text-zinc-900 font-bold focus:outline-none focus:border-[#E85A28] transition-colors resize-none"
                        />
                    </div>

                    <div className="flex justify-start pt-8">
                        <button type="submit" disabled={saving} className="bg-[#E85A28] hover:bg-[#D44D1F] disabled:opacity-50 text-white font-black py-4 px-16 rounded-xl transition-all shadow-lg shadow-orange-100 min-w-[240px]">
                            {saving ? "Saving..." : "Save Changes"}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}

function CameraIcon() {
    return <svg width="20" height="20" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M19.1667 15.8333V6.66667C19.1667 6.22464 18.9911 5.80072 18.6785 5.48816C18.366 5.17559 17.942 5 17.5 5H15.0167L13.8417 2.65C13.6845 2.33642 13.4382 2.07474 13.1311 1.89518C12.8239 1.71562 12.4691 1.6256 12.1083 1.63628H7.89171C7.53094 1.6256 7.17614 1.71562 6.86898 1.89518C6.56182 2.07474 6.31551 2.33642 6.15837 2.65L4.98337 5H2.50004C2.05801 5 1.63409 5.17559 1.32153 5.48816C1.00897 5.80072 0.833374 6.22464 0.833374 6.66667V15.8333C0.833374 16.2754 1.00897 16.6993 1.32153 17.0118C1.63409 17.3244 2.05801 17.5 2.50004 17.5H17.5C17.942 17.5 18.366 17.3244 18.6785 17.0118C18.9911 16.6993 19.1667 16.2754 19.1667 15.8333Z" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" /><path d="M10 14.1667C12.3012 14.1667 14.1667 12.3012 14.1667 10C14.1667 7.69882 12.3012 5.83334 10 5.83334C7.69886 5.83334 5.83337 7.69882 5.83337 10C5.83337 12.3012 7.69886 14.1667 10 14.1667Z" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" /></svg>
}

function ChevronDownIcon() {
    return <svg width="20" height="20" viewBox="0 0 20 20" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M5 7.5L10 12.5L15 7.5" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" /></svg>
