"use client";
import React, { useState } from "react";
import Image from "next/image";
import { Store, Camera, Smartphone, Laptop, Car, Home as HomeIcon, Footprints, Briefcase, Dog, Utensils, Construction, Tv, HeartPulse, Palette, Package, PlusCircle, Trophy } from "lucide-react";

const categories = [
  { name: "Post ad", src: "", icon: PlusCircle },
  { name: "Electronics", src: "/assets/images/laptop.svg", icon: Laptop },
  { name: "Mobiles", src: "/assets/images/phone.svg", icon: Smartphone },
  { name: "Vehicles", src: "/assets/images/car.svg", icon: Car },
  { name: "Property", src: "/assets/images/house.svg", icon: HomeIcon },
  { name: "Fashion", src: "/assets/images/bgshoe.svg", icon: Footprints },
  { name: "Business", src: "/assets/images/engineer.svg", icon: Briefcase },
  { name: "Sports", src: "", icon: Trophy },
  { name: "Pets", src: "/assets/images/pet.svg", icon: Dog },
];

export default function CategoryBar() {
  const [brokenImages, setBrokenImages] = useState<Record<string, boolean>>({});

  const handleImageError = (name: string) => {
    setBrokenImages((prev) => ({ ...prev, [name]: true }));
  };

  const renderIcon = (c: (typeof categories)[0]) => {
    if (brokenImages[c.name]) {
      const Icon = c.icon;
      return <Icon size={48} className="text-orange-600" />;
    }
    return (
      <Image
        src={c.src}
        alt={c.name}
        width={84}
        height={84}
        className="object-contain"
        onError={() => handleImageError(c.name)}
      />
    );
  };

  // Split categories into two rows
  const firstRow = categories.slice(0, 5);
  const secondRow = categories.slice(5);

  return (
    <div className="lg:hidden px-4 py-4 bg-white">
      {/* Title */}
      <h2 className="text-orange-600 font-bold text-lg mb-3">
        Browse by category
      </h2>

      {/* Rows Container */}
      <div className="flex flex-col gap-4">
        {[firstRow, secondRow].map((row, idx) => (
          <div key={idx} className="overflow-x-auto pb-2 scrollbar-hide">
            <div className="flex gap-4 snap-x snap-mandatory">
              {row.map((c) => (
                <div key={c.name} className="flex-none w-[100px] snap-center">
                  <div
                    className="w-[90px] h-[90px] mx-auto rounded-2xl p-2 flex items-center justify-center border-2 border-orange-100 bg-orange-50/30 shadow-sm transition-transform hover:scale-95 active:scale-90"
                  >
                    {renderIcon(c)}
                  </div>
                  <div className="mt-2 text-center text-[11px] font-bold text-zinc-700 leading-tight">
                    {c.name}
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

"use client";
import React, { useMemo, useState } from "react";
import AdCard from "./ui/AdCard";
import LocationDropdown from "./LocationDropdown";
import SelectDropdown from "./ui/SelectDropdown";

import type { AdItem } from "./ui/AdCard";

// ─── Star Rating Component ────────────────────────────────────────────────────
function StarRating({ value, max = 5 }: { value: number; max?: number }) {
  return (
    <span className="flex items-center gap-0.5">
      {Array.from({ length: max }).map((_, i) => (
        <svg
          key={i}
          width="18"
          height="18"
          viewBox="0 0 20 20"
          fill={i < value ? "#f97316" : "none"}
          stroke={i < value ? "#f97316" : "#d1d5db"}
          strokeWidth="1.5"
          xmlns="http://www.w3.org/2000/svg"
        >
          <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
        </svg>
      ))}
    </span>
  );
}

// ─── Chevron Icon ─────────────────────────────────────────────────────────────
function ChevronRight({ className = "" }: { className?: string }) {
  return (
    <svg width="18" height="18" viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="2" className={className}>
      <path d="M7.5 5l5 5-5 5" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}

// ─── Section Toggle ───────────────────────────────────────────────────────────
function FilterSection({
  label,
  open,
  onToggle,
  children,
}: {
  label: string;
  open: boolean;
  onToggle: () => void;
  children: React.ReactNode;
}) {
  return (
    <div className="border-t border-gray-100">
      <button
        type="button"
        onClick={onToggle}
        className="w-full flex items-center justify-between px-4 py-3.5"
        style={{ minHeight: 52 }}
      >
        <span
          className="font-semibold text-base"
          style={{ color: "#f97316" }}
        >
          {label}
        </span>
        <span
          className="text-xl font-light leading-none"
          style={{ color: "#9ca3af", lineHeight: 1 }}
        >
          {open ? "−" : "+"}
        </span>
      </button>
      {open && <div className="px-4 pb-4">{children}</div>}
    </div>
  );
}

// ─── Main Export ──────────────────────────────────────────────────────────────
export default function CategoryListingClient({
  items,
  title,
  brands,
}: {
  items: AdItem[];
  title: string;
  brands: string[];
}) {
  type ListingItem = AdItem & { priceRaw?: number; rating?: number; brand?: string };

  const [location, setLocation] = useState<string | undefined>(undefined);
  const [selectedConditions, setSelectedConditions] = useState<string[]>([]);
  const [selectedBrands, setSelectedBrands] = useState<string[]>([]);
  const [brandSearch, setBrandSearch] = useState<string>("");
  const [rating, setRating] = useState<number | undefined>(undefined);

  const [pricePreset, setPricePreset] = useState<string | undefined>(undefined);
  const [customMin, setCustomMin] = useState<string>("");
  const [customMax, setCustomMax] = useState<string>("");

  const [openLocation, setOpenLocation] = useState<boolean>(false);
  const [openPrice, setOpenPrice] = useState<boolean>(true);
  const [openCondition, setOpenCondition] = useState<boolean>(true);
  const [openBrand, setOpenBrand] = useState<boolean>(true);
  const [openRating, setOpenRating] = useState<boolean>(true);

  const [sortBy, setSortBy] = useState<string>("recommended");
  const [page, setPage] = useState<number>(1);
  const pageSize = 9;

  const customMinNum = customMin !== "" ? Number(customMin) : undefined;
  const customMaxNum = customMax !== "" ? Number(customMax) : undefined;

  const filtered = useMemo(() => {
    const minMaxFromPreset = (preset?: string) => {
      if (!preset) return { min: undefined as number | undefined, max: undefined as number | undefined };
      switch (preset) {
        case "under20000": return { min: undefined, max: 20000 };
        case "30000-40000": return { min: 30000, max: 40000 };
        case "40000-50000": return { min: 40000, max: 50000 };
        case "50000-60000": return { min: 50000, max: 60000 };
        case "above100000": return { min: 100000, max: undefined };
        default: return { min: undefined, max: undefined };
      }
    };

    const preset = minMaxFromPreset(pricePreset);

    return (items as ListingItem[])
      .filter((it) => {
        if (location && it.location && !it.location.toLowerCase().includes(location.toLowerCase())) return false;
        if (selectedConditions.length > 0) {
          if (!it.condition) return false;
          if (!selectedConditions.some((c) => it.condition!.toLowerCase().includes(c.toLowerCase()))) return false;
        }
        if (selectedBrands.length > 0) {
          if (!it.brand) return false;
          if (!selectedBrands.some((b) => it.brand!.toLowerCase() === b.toLowerCase())) return false;
        }
        if (rating !== undefined && (!it.rating || it.rating < rating)) return false;
        const price = typeof it.priceRaw === "number" ? it.priceRaw : undefined;
        if (preset.min !== undefined && price !== undefined && price < preset.min) return false;
        if (preset.max !== undefined && price !== undefined && price > preset.max) return false;
        if (customMinNum !== undefined && price !== undefined && price < customMinNum) return false;
        if (customMaxNum !== undefined && price !== undefined && price > customMaxNum) return false;
        return true;
      })
      .sort((a, b) => {
        if (sortBy === "lowest") return (a.priceRaw ?? 0) - (b.priceRaw ?? 0);
        if (sortBy === "highest") return (b.priceRaw ?? 0) - (a.priceRaw ?? 0);
        if (sortBy === "newest") return Number(b.id) - Number(a.id);
        return 0;
      });
  }, [items, location, selectedConditions, selectedBrands, rating, pricePreset, customMinNum, customMaxNum, sortBy]);

  const totalPages = Math.max(1, Math.ceil(filtered.length / pageSize));
  const paged = filtered.slice((page - 1) * pageSize, page * pageSize);

  const clearAll = () => {
    setLocation(undefined);
    setSelectedConditions([]);
    setSelectedBrands([]);
    setBrandSearch("");
    setRating(undefined);
    setPricePreset(undefined);
    setCustomMin("");
    setCustomMax("");
    setPage(1);
  };

  const filteredBrands = brands
    .map((b) => b.charAt(0).toUpperCase() + b.slice(1))
    .filter((b) => b.toLowerCase().includes(brandSearch.toLowerCase()));

  const priceOptions = [
    { id: "under20000", label: "Under ₦20000" },
    { id: "30000-40000", label: "₦30000 - ₦40000" },
    { id: "40000-50000", label: "₦40000 - ₦50000" },
    { id: "50000-60000", label: "₦50000 - ₦60000" },
    { id: "above100000", label: "Above ₦100000" },
  ];

  const conditionOptions = ["Brand New", "Nigeria Used", "Foreign Used", "Fairly Used"];

  const ratingOptions = [
    { value: 4, stars: [true, true, true, true, false] },
    { value: 3, stars: [true, true, true, false, false] },
    { value: 2, stars: [true, true, false, false, false] },
    { value: 1, stars: [true, false, false, false, false] },
  ];

  return (
    <div className="grid grid-cols-1 md:grid-cols-12 gap-6">
      {/* ── Sidebar ── */}
      <aside className="md:col-span-3">
        <div
          className="bg-white rounded-lg overflow-hidden"
          style={{ border: "1.5px solid #fed7aa" }}
        >
          {/* Header */}
          <div className="flex items-center justify-between px-4 py-3.5">
            <span className="font-bold text-base text-gray-900">Filters</span>
            <button
              onClick={clearAll}
              className="font-semibold text-sm"
              style={{ color: "#f97316" }}
            >
              Clear All
            </button>
          </div>

          {/* Location */}
          <div className="border-t border-gray-100">
            <button
              type="button"
              onClick={() => setOpenLocation((v) => !v)}
              className="w-full flex items-center justify-between px-4 py-3.5"
              style={{ minHeight: 52 }}
            >
              <span className="font-semibold text-base" style={{ color: "#f97316" }}>Location</span>
              <ChevronRight className="text-gray-400" />
            </button>
            {openLocation && (
              <div className="px-4 pb-4">
                <LocationDropdown
                  openOnMount={openLocation}
                  value={location ?? "Lagos"}
                  onChange={(l) => { setLocation(l); setPage(1); }}
                />
              </div>
            )}
          </div>

          {/* Price */}
          <FilterSection label="Price" open={openPrice} onToggle={() => setOpenPrice((v) => !v)}>
            <div className="space-y-3">
              {priceOptions.map(({ id, label }) => (
                <label key={id} className="flex items-center gap-2.5 cursor-pointer">
                  <input
                    type="radio"
                    name="price"
                    checked={pricePreset === id}
                    onChange={() => { setPricePreset(id); setPage(1); }}
                    className="h-4 w-4 cursor-pointer"
                    style={{ accentColor: "#f97316" }}
                  />
                  <span className="text-sm text-gray-700">{label}</span>
                </label>
              ))}
            </div>

            {/* Custom Price Range */}
            <div className="mt-4">
              <p className="text-sm font-semibold mb-2" style={{ color: "#f97316" }}>
                Custom Price Range
              </p>
              <div className="flex items-center gap-2">
                <input
                  value={customMin}
                  onChange={(e) => setCustomMin(e.target.value)}
                  className="w-full border rounded text-sm px-3 py-2 outline-none focus:ring-1"
                  style={{ borderColor: "#fed7aa", focusBorderColor: "#f97316" } as React.CSSProperties}
                  placeholder="₦10000"
                />
                <input
                  value={customMax}
                  onChange={(e) => setCustomMax(e.target.value)}
                  className="w-full border rounded text-sm px-3 py-2 outline-none"
                  style={{ borderColor: "#fed7aa" }}
                  placeholder="₦10000"
                />
                <button
                  onClick={() => setPage(1)}
                  className="flex-shrink-0 px-4 py-2 rounded text-sm font-semibold text-white"
                  style={{ background: "#f97316" }}
                >
                  GO
                </button>
              </div>
              {(customMin || customMax) && (
                <button
                  onClick={() => { setCustomMin(""); setCustomMax(""); }}
                  className="mt-2 text-sm font-medium"
                  style={{ color: "#f97316" }}
                >
                  Clear
                </button>
              )}
            </div>
          </FilterSection>

          {/* Condition */}
          <FilterSection label="Condition" open={openCondition} onToggle={() => setOpenCondition((v) => !v)}>
            <div className="space-y-3">
              {conditionOptions.map((opt) => (
                <label key={opt} className="flex items-center gap-3 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={selectedConditions.includes(opt)}
                    onChange={(e) => {
                      setSelectedConditions((s) =>
                        e.target.checked ? [...s, opt] : s.filter((c) => c !== opt)
                      );
                      setPage(1);
                    }}
                    className="h-4 w-4 rounded cursor-pointer"
                    style={{ accentColor: "#f97316" }}
                  />
                  <span className="text-sm text-gray-700">{opt}</span>
                </label>
              ))}
            </div>
          </FilterSection>

          {/* Brand */}
          <FilterSection label="Brand" open={openBrand} onToggle={() => setOpenBrand((v) => !v)}>
            {/* Search */}
            <div
              className="flex items-center rounded overflow-hidden mb-3"
              style={{ border: "1.5px solid #fed7aa" }}
            >
              <input
                value={brandSearch}
                onChange={(e) => setBrandSearch(e.target.value)}
                placeholder="Search brand"
                className="flex-1 text-sm px-3 py-2 outline-none bg-white"
              />
              <button
                className="flex-shrink-0 flex items-center justify-center px-3 py-2"
                style={{ background: "#f97316" }}
              >
                <svg width="16" height="16" viewBox="0 0 20 20" fill="none" stroke="white" strokeWidth="2.2">
                  <circle cx="9" cy="9" r="6" />
                  <path d="M15 15l-3-3" strokeLinecap="round" />
                </svg>
              </button>
            </div>

            {/* Brand checkboxes */}
            <div className="space-y-3">
              {filteredBrands.map((label) => {
                const selected = selectedBrands.some((b) => b.toLowerCase() === label.toLowerCase());
                return (
                  <label key={label} className="flex items-center gap-3 cursor-pointer">
                    <input
                      type="checkbox"
                      checked={selected}
                      onChange={(e) => {
                        setSelectedBrands((s) =>
                          e.target.checked
                            ? [...s, label]
                            : s.filter((x) => x.toLowerCase() !== label.toLowerCase())
                        );
                        setPage(1);
                      }}
                      className="h-4 w-4 rounded cursor-pointer"
                      style={{ accentColor: "#f97316" }}
                    />
                    <span className="text-sm text-gray-700">{label}</span>
                  </label>
                );
              })}
            </div>
          </FilterSection>

          {/* Rating */}
          <FilterSection label="Rating" open={openRating} onToggle={() => setOpenRating((v) => !v)}>
            <div className="space-y-3">
              {ratingOptions.map(({ value, stars }) => (
                <label key={value} className="flex items-center gap-2 cursor-pointer">
                  <input
                    type="radio"
                    name="rating"
                    checked={rating === value}
                    onChange={() => { setRating(value); setPage(1); }}
                    className="h-4 w-4 cursor-pointer"
                    style={{ accentColor: "#f97316" }}
                  />
                  <span className="flex items-center gap-0.5">
                    {stars.map((filled, i) => (
                      <svg
                        key={i}
                        width="18"
                        height="18"
                        viewBox="0 0 20 20"
                        fill={filled ? "#f97316" : "none"}
                        stroke={filled ? "#f97316" : "#d1d5db"}
                        strokeWidth="1.5"
                      >
                        <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
                      </svg>
                    ))}
                  </span>
                </label>
              ))}
            </div>
          </FilterSection>
        </div>
      </aside>

      {/* ── Listings ── */}
      <section className="md:col-span-9">
        <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between mb-4 gap-3">
          <div className="text-sm text-gray-700">
            Items found: <span className="font-semibold">{filtered.length}</span>
          </div>
          <div className="flex items-center gap-3 w-full sm:w-auto">
            <span className="text-sm text-gray-600">Sort By:</span>
            <SelectDropdown
              value={sortBy}
              onChange={(v) => { setSortBy(v || "recommended"); setPage(1); }}
              options={["recommended", "newest", "lowest", "highest"]}
            />
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {paged.length === 0 ? (
            <div className="p-6 bg-white border rounded-md col-span-full text-gray-500">
              No items match filters.
            </div>
          ) : (
            paged.map((it) => {
              const displayItem = { ...it };

              return (
                <div key={it.id} className="h-full">
                  <AdCard item={displayItem} />
                </div>
              );
            })
          )}
        </div>

        {/* Pagination */}
        <div className="mt-6 flex items-center justify-center gap-2">
          <button
            disabled={page === 1}
            onClick={() => setPage((p) => Math.max(1, p - 1))}
            className="px-3 py-1 border rounded text-sm bg-white disabled:opacity-40"
          >
            Previous
          </button>
          {Array.from({ length: totalPages }).map((_, i) => (
            <button
              key={i}
              onClick={() => setPage(i + 1)}
              className="px-3 py-1 border rounded text-sm"
              style={
                page === i + 1
                  ? { background: "#f97316", color: "#fff", borderColor: "#f97316" }
                  : { background: "#fff" }
              }
            >
              {i + 1}
            </button>
          ))}
          <button
            disabled={page === totalPages}
            onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
            className="px-3 py-1 border rounded text-sm bg-white disabled:opacity-40"
          >
            Next
          </button>
        </div>
      </section>
    </div>
  );
}

"use client";
import { useEffect, useState } from "react";
import Image from "next/image";
import { listActiveAds } from "@/services/ads.service";

interface FeaturedAd {
  id: number;
  price: string;
  title: string;
  desc: string;
  img: string;
  location: string;
  likes: number;
}

function Stars() {
  return (
    <div className="flex items-center gap-1">
      {[1, 2, 3, 4].map((i) => (
        <svg key={i} className="w-5 h-5 text-yellow-300" viewBox="0 0 24 24" fill="currentColor" xmlns="http://www.w3.org/2000/svg"><path d="M12 .587l3.668 7.431L24 9.748l-6 5.858L19.335 24 12 20.201 4.665 24 6 15.606 0 9.748l8.332-1.73L12 .587z"/></svg>
      ))}
      <svg className="w-5 h-5 text-slate-300" viewBox="0 0 24 24" fill="currentColor" xmlns="http://www.w3.org/2000/svg"><path d="M12 .587l3.668 7.431L24 9.748l-6 5.858L19.335 24 12 20.201 4.665 24 6 15.606 0 9.748l8.332-1.73L12 .587z"/></svg>
    </div>
  );
}

export default function FeaturedAds() {
  const [featured, setFeatured] = useState<FeaturedAd[]>([]);

  useEffect(() => {
    (async () => {
      try {
        const res = await listActiveAds();
        const data = (res.data || []).slice(0, 4).map((d: any) => ({
          id: d.id,
          price: `₦ ${Number(d.price).toLocaleString()}`,
          title: d.title,
          desc: d.description || "",
          img: d.image_url || "/assets/images/bgphone.svg",
          location: d.location || "Nigeria",
          likes: Math.floor(Math.random() * 50) + 10, // Mock likes for now as not in DB
        }));
        setFeatured(data);
      } catch (err) {
        console.error("Failed to fetch featured ads", err);
      }
    })();
  }, []);

  if (featured.length === 0) return null;

  return (
    <section className="max-w-[1400px] mx-auto px-4 lg:px-12 pb-16 mt-8">
      <h3 className="text-3xl font-extrabold text-[#FF6B35] mb-6">Featured Ads</h3>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {featured.map((it) => (
          <article
            key={it.id}
            className="relative rounded-2xl overflow-hidden bg-gradient-to-r from-[#C84312] to-[#DE5A28] p-4 lg:p-6 text-white shadow-lg flex flex-col lg:flex-row gap-4 lg:gap-6 min-h-[220px]"
          >
            <div className="absolute top-4 right-4 lg:block">
              <div className="w-9 h-9 bg-emerald-400 rounded-full flex items-center justify-center text-white font-bold">✓</div>
            </div>

            <div className="flex-shrink-0 relative w-full lg:w-[300px] lg:h-[300px]">
              <div className="relative w-full rounded-xl overflow-hidden border-4 border-white p-1 bg-white h-full">
                <div className="relative w-full pb-[66%] lg:pb-0 lg:h-full">
                  <Image src={it.img} alt={it.title} fill className="absolute inset-0 object-cover" />
                </div>
              </div>

              <div className="absolute top-3 right-3">
                <div className="w-8 h-8 bg-white/90 rounded-full flex items-center justify-center text-gray-600">♡</div>
              </div>
            </div>

            <div className="flex-1 flex flex-col justify-between">
              <div>
                <div className="flex items-start justify-between">
                  <div>
                    <p className="text-white font-extrabold text-lg sm:text-xl">{it.price}</p>
                    <h4 className="mt-2 text-white text-xl sm:text-2xl font-semibold">{it.title}</h4>
                  </div>
                </div>

                <p className="mt-3 text-white/90 text-sm leading-relaxed line-clamp-3 sm:line-clamp-4">{it.desc}</p>

                <div className="mt-4 flex items-center gap-3">
                  <Stars />
                </div>

                <div className="mt-4 flex items-center gap-3 text-sm text-white/90">
                  <span className="flex items-center gap-2">📍 <span>{it.location}</span></span>
                  <span className="ml-auto flex items-center gap-2">👍 <span className="font-semibold">{it.likes}</span></span>
                </div>
              </div>
            </div>
          </article>
        ))}
      </div>
      <div className="mt-8 flex justify-center">
        <button className="bg-[#DE5A28] px-12 py-3 rounded-md font-semibold shadow-lg text-white">Shop Now!</button>
      </div>
    </section>
  );
}

"use client";

import Image from "next/image";
import { listActiveAds } from "@/services/ads.service";
import { Heart } from "lucide-react";
import { useFavorites } from "@/context/FavoritesProvider";

interface HotDeal {
  id: number;
  title: string;
  price: string;
  img: string;
  location: string;
  newLabel?: string;
}

import { useEffect, useState, useRef } from "react";

export default function HotDeals() {
  const scrollRef = useRef<HTMLDivElement>(null);
  const [list, setList] = useState<HotDeal[]>([]);

  useEffect(() => {
    (async () => {
      try {
        const res = await listActiveAds();
        const mapped: HotDeal[] = (res.data || []).reverse().slice(0, 8).map((d: any) => ({
          id: d.id,
          title: d.title,
          price: `₦ ${Number(d.price).toLocaleString()}`,
          img: d.image_url || "/assets/images/bgphone.svg",
          location: d.location || d.city || "Nigeria",
          newLabel: d.condition || "Brand New",
        }));
        setList(mapped);
      } catch (err) {}
    })();
  }, []);

  const { isFavorite, toggle } = useFavorites();

  const scrollLeft = () => {
    scrollRef.current?.scrollBy({
      left: -320,
      behavior: "smooth",
    });
  };

  const scrollRight = () => {
    scrollRef.current?.scrollBy({
      left: 320,
      behavior: "smooth",
    });
  };

  return (
    <section className="max-w-[1400px] mx-auto px-6 lg:px-12 pb-16 mt-10">
      {/* HEADER */}
      <div className="relative flex items-center mb-10">
        <h3
          className="absolute left-1/2 -translate-x-1/2 
  whitespace-nowrap 
  text-2xl sm:text-3xl md:text-4xl lg:text-5xl 
  font-extrabold text-black text-center"
        >
          Hot Deals <span className="text-[#FF6B35]">Today!</span>
        </h3>

        <div className="ml-auto hidden md:flex">
          <a
            href="#"
            className="text-sm font-medium text-gray-700 hover:text-[#FF6B35] transition"
          >
            See more
          </a>
        </div>
      </div>

      {/* CAROUSEL on lg, mobile-first: 2-column grid */}
      <div className="relative">
        {/* LEFT CHEVRON */}
        <button
          aria-label="Scroll left"
          onClick={scrollLeft}
          className="hidden lg:flex absolute left-0 top-1/2 -translate-y-1/2 -translate-x-6 z-20 bg-[#FF6B35] w-14 h-14 rounded-full items-center justify-center text-white shadow-lg hover:bg-[#FF5520] transition"
        >
          <svg
            className="w-6 h-6"
            fill="none"
            stroke="currentColor"
            strokeWidth="2.5"
            viewBox="0 0 24 24"
          >
            <path d="M15 19l-7-7 7-7" />
          </svg>
        </button>

        {/* SCROLL CONTAINER: grid on mobile (2 cols, equal rows), carousel on lg */}
        <div
          ref={scrollRef}
          className={
            "flex gap-4 overflow-x-auto pb-6 scroll-smooth snap-x snap-mandatory lg:gap-6 " +
            "[&::-webkit-scrollbar]:hidden [-ms-overflow-style:none] [scrollbar-width:none]"
          }
        >
          {list.map((item) => (
            <div
              key={item.id}
              className="relative shrink-0 w-[260px] sm:w-[240px] md:w-[260px] lg:min-w-[260px] bg-white rounded-[24px] border-2 border-[#FF6B35] px-4 pt-4 pb-5 shadow-sm h-full flex flex-col snap-start min-h-[320px] lg:min-h-0"
            >
              {/* HOT BADGE */}
              <div className="absolute -top-3 left-3 z-10">
                <div className="relative">
                  <div className="bg-[#FF6B35] text-white text-sm font-bold px-4 py-1.5 rounded-r-lg">
                    Hot 🔥
                  </div>
                  <div className="absolute left-0 -bottom-2 w-0 h-0 border-t-[8px] border-t-[#FF6B35] border-r-[8px] border-r-transparent" />
                </div>
              </div>

                  {/* HEART */}
                  {
                    (() => {
                      const fav = isFavorite(item.id);
                      return (
                        <button
                          onClick={(e) => {
                            e.preventDefault();
                            e.stopPropagation();
                            toggle({
                              id: item.id,
                              title: item.title,
                              price: item.price,
                              img: item.img,
                              desc: undefined,
                              location: item.location,
                              likes: 0,
                            });
                          }}
                          aria-label={fav ? "Remove from favorites" : "Add to favorites"}
                          className={`absolute top-3 right-3 z-20 bg-white/90 backdrop-blur-sm rounded-full p-1 shadow ${fav ? "text-red-500" : "text-gray-400"}`}
                        >
                          <Heart className="w-5 h-5" />
                        </button>
                      );
                    })()
                  }

              {/* IMAGE */}
              <div className="mt-6 relative flex-none">
                <div className="bg-[#F7F7F7] rounded-2xl p-3 sm:p-6 shadow-md rotate-[-1deg] sm:rotate-[-2deg]">
                  <div className="relative w-full pb-[66%] sm:pb-[60%] lg:pb-0 lg:h-[180px]">
                    <Image
                      src={item.img}
                      alt={item.title}
                      fill
                      className="absolute inset-0 object-cover"
                    />
                  </div>
                </div>

                {/* VERIFIED */}
                <div className="absolute right-0 bottom-2">
                  <div className="w-7 h-7 bg-emerald-500 rounded-full flex items-center justify-center text-white shadow">
                    <svg
                      className="w-4 h-4"
                      fill="none"
                      stroke="currentColor"
                      strokeWidth="3"
                      viewBox="0 0 24 24"
                    >
                      <path d="M5 13l4 4L19 7" />
                    </svg>
                  </div>
                </div>
              </div>

              {/* PRICE & TITLE */}
              <div className="mt-4 flex-1">
                <p className="text-[#FF6B35] font-extrabold text-xl sm:text-2xl">
                  {item.price}
                </p>
                <h4 className="mt-1 font-semibold text-base sm:text-lg text-black line-clamp-2">
                  {item.title}
                </h4>
              </div>

              {/* RATING */}
              <div className="mt-1.5 flex gap-0.5">
                {[1, 2, 3, 4].map((i) => (
                  <svg
                    key={i}
                    className="w-5 h-5 text-[#FF6B35]"
                    viewBox="0 0 24 24"
                    fill="currentColor"
                  >
                    <path d="M12 .587l3.668 7.431L24 9.748l-6 5.858L19.335 24 12 20.201 4.665 24 6 15.606 0 9.748l8.332-1.73L12 .587z" />
                  </svg>
                ))}
                <svg
                  className="w-5 h-5 text-gray-300"
                  viewBox="0 0 24 24"
                  fill="currentColor"
                >
                  <path d="M12 .587l3.668 7.431L24 9.748l-6 5.858L19.335 24 12 20.201 4.665 24 6 15.606 0 9.748l8.332-1.73L12 .587z" />
                </svg>
              </div>

              {/* LOCATION */}
              <div className="mt-3 flex items-center justify-between text-sm">
                <div className="flex items-center gap-1.5 text-gray-600">
                  <span>📍</span>
                  <span>{item.location}</span>
                </div>
                {item.newLabel && (
                  <span className="font-medium text-gray-700">
                    {item.newLabel}
                  </span>
                )}
              </div>
            </div>
          ))}
        </div>

        {/* RIGHT CHEVRON */}
        <button
          aria-label="Scroll right"
          onClick={scrollRight}
          className="hidden lg:flex absolute right-0 top-1/2 -translate-y-1/2 translate-x-6 z-20 bg-[#FF6B35] w-14 h-14 rounded-full items-center justify-center text-white shadow-lg hover:bg-[#FF5520] transition"
        >
          <svg
            className="w-6 h-6"
            fill="none"
            stroke="currentColor"
            strokeWidth="2.5"
            viewBox="0 0 24 24"
          >
            <path d="M9 5l7 7-7 7" />
          </svg>
        </button>
      </div>
    </section>
  );
}

