"use client";

import React, { createContext, useContext, useEffect, useState } from "react";

export type FavoriteItem = {
  id: number | string;
  title: string;
  price?: string;
  img?: string;
  desc?: string;
  location?: string;
  likes?: number;
};

type FavoritesContextType = {
  items: FavoriteItem[];
  toggle: (item: FavoriteItem) => void;
  isFavorite: (id: string | number) => boolean;
  remove: (id: string | number) => void;
};

const FavoritesContext = createContext<FavoritesContextType | undefined>(
  undefined,
);

const STORAGE_KEY = "234deals_favorites_v1";

export function FavoritesProvider({ children }: { children: React.ReactNode }) {
  const [items, setItems] = useState<FavoriteItem[]>([]);

  useEffect(() => {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) setItems(JSON.parse(raw));
    } catch (e) {
      // ignore
    }
  }, []);

  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(items));
    } catch (e) {
      // ignore
    }
  }, [items]);

  function isFavorite(id: string | number) {
    return items.some((i) => String(i.id) === String(id));
  }

  function toggle(item: FavoriteItem) {
    setItems((prev) => {
      const exists = prev.some((p) => String(p.id) === String(item.id));
      if (exists) return prev.filter((p) => String(p.id) !== String(item.id));
      return [...prev, item];
    });
  }

  function remove(id: string | number) {
    setItems((prev) => prev.filter((p) => String(p.id) !== String(id)));
  }

  return (
    <FavoritesContext.Provider value={{ items, toggle, isFavorite, remove }}>
      {children}
    </FavoritesContext.Provider>
  );
}

export function useFavorites() {
  const ctx = useContext(FavoritesContext);
  if (!ctx) throw new Error("useFavorites must be used within FavoritesProvider");
  return ctx;
}

export default FavoritesProvider;

export const API_BASE =
  process.env.NEXT_PUBLIC_API_URL || "http://localhost:5001/api";

type HttpMethod = "GET" | "POST" | "PUT" | "DELETE";

async function apiFetch<T>(
  path: string,
  options: { method?: HttpMethod; body?: unknown; auth?: boolean } = {}
): Promise<T> {
  const url = `${API_BASE.replace(/\/$/, "")}/${path.replace(/^\//, "")}`;
  const headers: Record<string, string> = { "Content-Type": "application/json" };
  if (options.auth) {
    if (typeof window !== "undefined") {
      const token = window.localStorage.getItem("token");
      if (token) headers["Authorization"] = `Bearer ${token}`;
    }
  }
  const res = await fetch(url, {
    method: options.method || "GET",
    headers,
    body: options.body ? JSON.stringify(options.body) : undefined,
    cache: "no-store",
  });
  const data = await res.json().catch(() => ({}));
  if (!res.ok) {
    const message =
      (data && (data.message || data.error)) ||
      `Request failed with status ${res.status}`;
    throw new Error(message);
  }
  return data as T;
}

